import i18n from "@/i18n";
import { useTranslation } from "react-i18next";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { MapPin, X, Loader2, CheckCircle2, LogOut, Users, Plane } from "lucide-react";
import { checkIn, checkOut, getMyCheckIn, fetchCityTravelers, CheckIn } from "@/lib/checkInService";
import { getCurrentLocation } from "@/lib/locationService";
import { useAuth } from "@/hooks/useAuth";
interface Props {
  open: boolean;
  onClose: () => void;
  onCheckInSuccess: (checkInData: CheckIn, travelers: any[]) => void;
}
export default function CheckInModal({
  open,
  onClose,
  onCheckInSuccess
}: Props) {
  const {
    t
  } = useTranslation();
  const {
    user
  } = useAuth();
  const [step, setStep] = useState<"idle" | "locating" | "confirming" | "done">("idle");
  const [city, setCity] = useState("");
  const [country, setCountry] = useState("");
  const [lat, setLat] = useState(0);
  const [lng, setLng] = useState(0);
  const [error, setError] = useState("");
  const [nearbyCount, setNearbyCount] = useState(0);
  const [currentCheckIn, setCurrentCheckIn] = useState<CheckIn | null>(null);
  useEffect(() => {
    if (open && user) {
      getMyCheckIn(user.id).then(ci => {
        if (ci) {
          setCurrentCheckIn(ci);
          setCity(ci.city);
          setCountry(ci.country);
          fetchCityTravelers(ci.city, user.id).then(t => setNearbyCount(t.length));
          setStep("done");
        } else {
          // 재오픈 시 이전 상태 초기화
          setCurrentCheckIn(null);
          setStep("idle");
          setCity("");
          setCountry("");
          setError("");
          setNearbyCount(0);
        }
      });
    }
  }, [open, user]);
  const handleLocate = async () => {
    setError("");
    setStep("locating");
    const pos = await getCurrentLocation(false);
    if (!pos) {
      setError(i18n.t("checkin.perm_req", { defaultValue: "Location permission is required." }));
      setStep("idle");
      return;
    }
    const { lat: latitude, lng: longitude } = pos;
    setLat(latitude);
    setLng(longitude);
    // 역지오코딩
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&accept-language=ko`, {
        headers: {
          "User-Agent": "MigoApp/1.0"
        }
      });
      const data = await res.json();
      const addr = data.address || {};
      const detectedCity = addr.city || addr.town || addr.village || addr.county || addr.state || i18n.t("checkin.unknown_city");
      const detectedCountry = addr.country || i18n.t("checkin.unknown_country");
      setCity(detectedCity);
      setCountry(detectedCountry);
      setStep("confirming");
    } catch {
      setError(i18n.t("checkin.fetch_failed"));
      setStep("idle");
    }
  };
  const handleConfirm = async () => {
    if (!user) return;
    setStep("locating");
    const {
      data,
      error: err
    } = await checkIn(user.id, lat, lng);
    if (err || !data) {
      console.error("[CheckIn Error]", err);
      const msg = err?.message ? `Error: ${err.message}` : i18n.t("checkin.error_occurred");
      setError(msg);
      setStep("idle");
      return;
    }
    const travelers = await fetchCityTravelers(data.city, user.id);
    setNearbyCount(travelers.length);
    setCurrentCheckIn(data);
    setStep("done");
    onCheckInSuccess(data, travelers);
  };
  const handleCheckOut = async () => {
    if (!user) return;
    await checkOut(user.id);
    setCurrentCheckIn(null);
    setStep("idle");
    setCity("");
    setCountry("");
    setNearbyCount(0);
  };
  const expiresHours = currentCheckIn ? Math.max(0, Math.round((new Date(currentCheckIn.expires_at).getTime() - Date.now()) / 3600000)) : 0;
  return <AnimatePresence>
      {open && <motion.div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm" initial={{
      opacity: 0
    }} animate={{
      opacity: 1
    }} exit={{
      opacity: 0
    }} onClick={e => {
      if (e.target === e.currentTarget) onClose();
    }}>
          <motion.div className="w-full max-w-md bg-card rounded-3xl mb-4 sm:mb-8 shadow-2xl overflow-hidden" style={{
        paddingBottom: "calc(env(safe-area-inset-bottom, 0px) + var(--nav-height) + 1rem)"
      }} initial={{
        y: "100%"
      }} animate={{
        y: 0
      }} exit={{
        y: "100%"
      }} transition={{
        type: "spring",
        damping: 28,
        stiffness: 300
      }}>
            <div className="max-h-[75vh] overflow-y-auto px-6 pt-6">
            {/* Header */}
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                  <Plane className="text-primary" size={16} />
                </div>
                <h2 className="font-bold text-lg truncate">{t("checkin.title")}</h2>
              </div>
              <button onClick={onClose} className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                <X size={16} />
              </button>
            </div>

            {/* Step: idle */}
            {step === "idle" && <div className="space-y-4">
                <div className="bg-primary/5 rounded-2xl p-4 text-sm text-muted-foreground leading-relaxed truncate">{t("checkin.desc1")}<span className="text-primary font-bold truncate">{t("checkin.desc2")}</span>{t("checkin.desc3")}</div>
                {error && <p className="text-xs text-red-500 text-center">{error}</p>}
                <button onClick={handleLocate} className="w-full py-4 rounded-2xl bg-primary text-primary-foreground font-bold flex items-center justify-center gap-2 active:scale-95 transition-transform">
                  <MapPin size={20} />{t("checkin.detect_btn")}</button>
              </div>}

            {/* Step: locating */}
            {step === "locating" && <div className="flex flex-col items-center gap-4 py-8">
                <Loader2 className="text-primary animate-spin" size={40} />
                <p className="text-sm text-muted-foreground truncate">{t("checkin.locating")}</p>
              </div>}

            {/* Step: confirming */}
            {step === "confirming" && <div className="space-y-5">
                <div className="bg-muted rounded-2xl p-5 flex flex-col items-center gap-2 text-center">
                  <MapPin className="text-primary" size={32} />
                  <p className="text-2xl font-extrabold">{city}</p>
                  <p className="text-sm text-muted-foreground">{country}</p>
                </div>
                <p className="text-sm text-muted-foreground text-center truncate">{t("checkin.confirm_desc")}</p>
                <div className="flex gap-3">
                  <button onClick={() => setStep("idle")} className="flex-1 py-3 rounded-2xl border border-border font-semibold text-sm text-muted-foreground">{t("checkin.cancel")}</button>
                  <button onClick={handleConfirm} className="flex-1 py-3 rounded-2xl bg-primary text-primary-foreground font-bold text-sm">{t("checkin.checkin_btn")}</button>
                </div>
              </div>}

            {/* Step: done */}
            {step === "done" && <div className="space-y-5">
                {/* 체크인 완료 뱃지 */}
                <div className="bg-gradient-to-br from-primary/20 to-purple-500/10 rounded-2xl p-5 flex flex-col items-center gap-2 text-center">
                  <div className="flex items-center gap-2">
                    <CheckCircle2 className="text-primary" size={28} />
                    <span className="font-extrabold text-lg text-primary truncate">{t("checkin.done_badge")}</span>
                  </div>
                  <p className="text-3xl font-extrabold mt-1">{city}</p>
                  <p className="text-sm text-muted-foreground">{country}</p>
                  <div className="flex items-center gap-1 mt-2 bg-primary/10 rounded-full px-3 py-1">
                    <Users size={12} className="text-primary" />
                    <span className="text-xs font-bold text-primary truncate">{nearbyCount}{t("checkin.people_here")}</span>
                  </div>
                  <p className="text-xs text-muted-foreground mt-1 truncate">{expiresHours}{t("checkin.expires")}</p>
                </div>
                <button onClick={handleCheckOut} className="w-full py-3 rounded-2xl border border-red-300/50 text-red-500 font-semibold text-sm flex items-center justify-center gap-2">
                  <LogOut size={16} />{t("checkin.checkout_btn")}</button>
              </div>}
            </div>{/* end scrollable content */}
          </motion.div>
        </motion.div>}
    </AnimatePresence>;
}

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/lib/supabaseClient";
import { Heart, Star, MapPin, Clock, ChevronRight, Sparkles } from "lucide-react";

interface DailyPick {
  id: string;
  name: string;
  age: number;
  photo_url: string;
  nationality: string;
  location: string;
  bio: string;
  interests: string[];
  verified: boolean;
  like_count: number;
}

export default function DailyPicksCard({ onProfileClick }: { onProfileClick?: (id: string) => void }) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [picks, setPicks] = useState<DailyPick[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [timeLeft, setTimeLeft] = useState("");

  useEffect(() => {
    if (!user) return;
    loadDailyPicks();
  }, [user]);

  // 자정까지 남은 시간 카운트다운
  useEffect(() => {
    const update = () => {
      const now = new Date();
      const midnight = new Date(now);
      midnight.setHours(24, 0, 0, 0);
      const diff = midnight.getTime() - now.getTime();
      const h = Math.floor(diff / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      setTimeLeft(`${h}h ${m}m`);
    };
    update();
    const interval = setInterval(update, 60000);
    return () => clearInterval(interval);
  }, []);

  const loadDailyPicks = async () => {
    if (!user) return;

    // 날짜 기반 시드로 일관된 추천 (같은 날 같은 3명)
    const today = new Date().toISOString().split("T")[0];
    const cached = sessionStorage.getItem(`migo_daily_picks_${today}`);
    if (cached) {
      setPicks(JSON.parse(cached));
      return;
    }

    // 내 정보
    const { data: me } = await supabase
      .from("profiles")
      .select("interests, languages")
      .eq("id", user.id)
      .single();

    // 프로필 가져오기 (모의 유저 포함, 사진 있는 사람만, 정지계정 제외)
    const { data: profiles } = await supabase
      .from("profiles")
      .select("id, name, age, photo_url, nationality, location, bio, interests, verified")
      .neq("id", user.id)
      .or('is_banned.is.null,is_banned.eq.false')
      .or('banned.is.null,banned.eq.false')
      .not("photo_url", "is", null)
      .limit(30);

    if (!profiles || profiles.length === 0) return;

    // 공통 관심사 기반 점수 매기기
    const myInterests = me?.interests || [];
    const scored = profiles.map((p) => {
      const common = (p.interests || []).filter((i: string) => myInterests.includes(i)).length;
      return { ...p, score: common * 10 + (p.verified ? 5 : 0) + Math.random() * 3 };
    });
    scored.sort((a, b) => b.score - a.score);

    // 상위 3명 + 좋아요 수 가져오기
    const top3 = scored.slice(0, 3);
    const pickResults: DailyPick[] = [];

    for (const p of top3) {
      const { count } = await supabase
        .from("likes")
        .select("*", { count: "exact", head: true })
        .eq("to_user", p.id);

      pickResults.push({
        id: p.id,
        name: p.name,
        age: p.age || 25,
        photo_url: p.photo_url,
        nationality: p.nationality || "",
        location: p.location || "",
        bio: p.bio || "",
        interests: p.interests || [],
        verified: p.verified,
        like_count: count || 0,
      });
    }

    setPicks(pickResults);
    sessionStorage.setItem(`migo_daily_picks_${today}`, JSON.stringify(pickResults));
  };

  if (picks.length === 0) return null;

  const pick = picks[currentIdx];

  return (
    <div className="px-4 pb-2">
      <motion.div
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-card rounded-2xl border border-border/50 shadow-sm overflow-hidden"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-3 pt-2.5 pb-1">
          <div className="flex items-center gap-1.5">
            <Sparkles size={13} className="text-amber-500" />
            <span className="text-[11px] font-extrabold text-foreground">
              {t("daily.title", "오늘의 추천 매치")}
            </span>
            <span className="text-[9px] px-1.5 py-0.5 rounded-full bg-primary/10 text-primary font-bold">
              💫 {t("daily.best", "Best")}
            </span>
          </div>
          <div className="flex items-center gap-1 text-[9px] text-muted-foreground">
            <Clock size={10} />
            <span>{timeLeft}</span>
          </div>
        </div>

        {/* Profile cards row */}
        <div className="flex gap-2 px-3 pb-3 pt-1 overflow-x-auto scrollbar-none">
          {picks.map((p, i) => (
            <motion.button
              key={p.id}
              whileTap={{ scale: 0.96 }}
              onClick={() => {
                setCurrentIdx(i);
                onProfileClick?.(p.id);
              }}
              className={`relative shrink-0 w-[110px] rounded-xl overflow-hidden border-2 transition-all ${
                i === currentIdx ? "border-primary shadow-lg" : "border-transparent"
              }`}
            >
              {/* Photo */}
              <div className="h-[130px] relative">
                <img
                  src={p.photo_url}
                  alt={p.name}
                  className="w-full h-full object-cover pointer-events-auto"
                  loading="lazy"
                />
                {/* Gradient overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent" />

                {/* Verified badge */}
                {p.verified && (
                  <div className="absolute top-1.5 right-1.5 w-4 h-4 rounded-full bg-primary flex items-center justify-center">
                    <Star size={8} className="text-white" fill="white" />
                  </div>
                )}

                {/* Like count */}
                <div className="absolute top-1.5 left-1.5 flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-red-500/80 backdrop-blur-sm">
                  <Heart size={8} className="text-white" fill="white" />
                  <span className="text-[8px] font-bold text-white">{p.like_count}</span>
                </div>

                {/* Name & info */}
                <div className="absolute bottom-1.5 left-1.5 right-1.5">
                  <p className="text-white text-[11px] font-extrabold truncate">
                    {p.name}, {p.age}
                  </p>
                  <div className="flex items-center gap-0.5">
                    <MapPin size={8} className="text-white/70" />
                    <p className="text-white/80 text-[8px] truncate">{p.location || p.nationality}</p>
                  </div>
                </div>
              </div>

              {/* Tags */}
              <div className="px-1.5 py-1.5 bg-card">
                <div className="flex flex-wrap gap-0.5">
                  {(p.interests || []).slice(0, 2).map((tag) => (
                    <span key={tag} className="text-[7px] px-1 py-0.5 rounded bg-muted text-muted-foreground font-medium truncate">
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            </motion.button>
          ))}
        </div>

        {/* Dots */}
        <div className="flex justify-center gap-1 pb-2">
          {picks.map((_, i) => (
            <div
              key={i}
              className={`w-1.5 h-1.5 rounded-full transition-all ${
                i === currentIdx ? "bg-primary w-4" : "bg-border"
              }`}
            />
          ))}
        </div>
      </motion.div>
    </div>
  );
}

