import i18n from "@/i18n";
import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from "react";
import React from "react";
import { supabase } from "@/lib/supabaseClient";
import { useAuth } from "@/hooks/useAuth";
export interface GroupThread {
  id: string;
  name: string;
  photo: string;
  lastMessage: string;
  time: string;
  unread: number;
  online: boolean;
  isGroup?: boolean;
  memberCount?: number;
  memberPhotos?: string[];
  groupWelcome?: string;
  opponentId?: string;
  createdAt?: string;
}
interface ChatContextType {
  totalUnread: number;
  threads: GroupThread[];
  markRead: (chatId: string) => void;
  addUnread: (chatId: string, count?: number) => void;
  resetAll: () => void;
  setOpenThread: (chatId: string | null) => void;
  createGroupThread: (group: {
    id: string;
    title: string;
    hostPhoto: string;
    memberPhotos: string[];
    currentMembers: number;
    destination: string;
  }) => string;
}
const ChatContext = createContext<ChatContextType>({
  totalUnread: 0,
  threads: [],
  markRead: () => {},
  addUnread: () => {},
  resetAll: () => {},
  setOpenThread: () => {},
  createGroupThread: () => ""
});
export const useChatContext = () => useContext(ChatContext);
export const ChatProvider = ({
  children
}: {
  children: ReactNode;
}) => {
  const { user, sessionReady } = useAuth();
  const [threads, setThreads] = useState<GroupThread[]>([]);
  const [unreadMap, setUnreadMap] = useState<Record<string, number>>(() => {
    try {
      const stored = localStorage.getItem('migo_unread_map');
      return stored ? JSON.parse(stored) : {};
    } catch { return {}; }
  });
  const [openThread, setOpenThread] = useState<string | null>(null);
  const openThreadRef = React.useRef<string | null>(null);

  const handleSetOpenThread = useCallback((chatId: string | null) => {
    setOpenThread(chatId);
    openThreadRef.current = chatId;
  }, []);
  const totalUnread = Object.values(unreadMap).reduce((s, n) => s + n, 0);
  const fetchThreads = useCallback(async () => {
    if (!user || !sessionReady) return; // sessionReady: auth lockAcquired 완료 후 실행

    // [1] 내가 속한 스레드 목록 (single query)
    const {
      data,
      error
    } = await supabase.from('chat_members').select('thread_id, chat_threads ( id, is_group, created_at )').eq('user_id', user.id);
    if (error || !data) return;
    const threadIds = data.map((m: any) => m.chat_threads?.id).filter(Boolean);
    if (threadIds.length === 0) {
      setThreads([]);
      return;
    }

    // [2] N+1 제거: 모든 멤버+프로필 + 마지막 메시지를 병렬 배치 처리
    const [membersRes, msgsRes] = await Promise.all([supabase.from('chat_members').select('thread_id, user_id, profiles ( name, photo_url )').in('thread_id', threadIds), supabase.from('messages').select('thread_id, text, created_at').in('thread_id', threadIds).order('created_at', {
      ascending: false
    })]);

    // 스레드별 마지막 메시지 맵 (이미 created_at DESC 정렬됨)
    const lastMsgMap: Record<string, any> = {};
    for (const msg of msgsRes.data || []) {
      if (!lastMsgMap[msg.thread_id]) lastMsgMap[msg.thread_id] = msg;
    }

    // 스레드별 멤버 맵
    const membersByThread: Record<string, any[]> = {};
    for (const m of membersRes.data || []) {
      (membersByThread[m.thread_id] ||= []).push(m);
    }

    let localUnreadMap: Record<string, number> = {};
    try { localUnreadMap = JSON.parse(localStorage.getItem('migo_unread_map') || '{}'); } catch {}

    const mapped: GroupThread[] = data.map((m: any) => {
      const thread = m.chat_threads;
      if (!thread) return null;
      const members = membersByThread[thread.id] || [];
      const others = members.filter((mb: any) => mb.user_id !== user.id);
      const lastMsg = lastMsgMap[thread.id] || null;
      let name = thread.is_group ? i18n.t("chat.groupChat", "Group Chat") : "";
      let photo = "";
      let memberPhotos: string[] = [];
      if (!thread.is_group) {
        const p = others[0]?.profiles;
        if (p) {
          name = p.name || i18n.t("chat.unknownUser", "Unknown User");
          photo = p.photo_url || "";
        } else {
          name = i18n.t("chat.unknownUser", "Unknown User");
        }
      } else {
        memberPhotos = members.map((mb: any) => mb.profiles?.photo_url).filter(Boolean);
        name = i18n.t("chat.groupChat") || "Group Chat";
      }
      return {
        id: thread.id,
        name,
        photo,
        lastMessage: lastMsg?.text ?? "New conversation",
        time: lastMsg ? new Intl.DateTimeFormat(i18n.language || 'en', {
          hour: 'numeric',
          minute: 'numeric'
        }).format(new Date(lastMsg.created_at)) : "",
        unread: localUnreadMap[thread.id] || 0,
        online: false, // 실제 온라인 여부를 서버에서 확인하지 않으므로 false (true 하드코딩은 사용자 오해 유발)
        isGroup: thread.is_group,
        memberCount: members.length || 2,
        memberPhotos,
        opponentId: !thread.is_group ? others[0]?.user_id : undefined,
        createdAt: thread.created_at
      } as GroupThread;
    }).filter(Boolean) as GroupThread[];
    setThreads(mapped);
  }, [user, sessionReady]);
  useEffect(() => {
    if (!user || !sessionReady) return; // sessionReady: auth lockAcquired 완료 후 실행
    fetchThreads();

    // ── 3개 채널 → 단일 채널로 병합 (WebSocket 연결 1/3로 절감) ──
    // matches INSERT debounce: 연속 매치 시 rerender 폭탄 방지
    let matchDebounceTimer: ReturnType<typeof setTimeout> | null = null;

    const chatChannel = supabase.channel(`chat_ctx:${user.id}`)
      // 새 메시지 → lastMessage 실시간 업데이트
      // 주의: Supabase 동적 filter(IN)는 지원되지 않으상 thread_id 컴마 리스트 불가 
      // 따라서 내가 속한 thread인지 setThreads에서 확인 (기존 구조 유지)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages'
      }, payload => {
        const newMsg = payload.new as any;
        setThreads(prev => prev.map(th => {
          if (th.id !== newMsg.thread_id) return th;
          return {
            ...th,
            lastMessage: newMsg.text,
            time: new Intl.DateTimeFormat(i18n.language || 'en', {
              hour: 'numeric',
              minute: 'numeric'
            }).format(new Date(newMsg.created_at)),
            unread: newMsg.sender_id !== user.id && newMsg.thread_id !== openThreadRef.current ? th.unread + 1 : th.unread
          };
        }));
        if (newMsg.sender_id !== user.id && newMsg.thread_id !== openThreadRef.current) {
          setUnreadMap(prev => {
            const next = {
              ...prev,
              [newMsg.thread_id]: (prev[newMsg.thread_id] || 0) + 1
            };
            try { localStorage.setItem('migo_unread_map', JSON.stringify(next)); } catch {}
            return next;
          });
        }
      })
      // 새 매칭 → thread 목록 리로드 (debounce 500ms: 연속 INSERT 시 1회만)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'matches'
      }, () => {
        if (matchDebounceTimer) clearTimeout(matchDebounceTimer);
        matchDebounceTimer = setTimeout(() => {
          fetchThreads();
          matchDebounceTimer = null;
        }, 500);
      })
      // 스레드 삭제 → 실시간 UI 반영
      .on('postgres_changes', {
        event: 'DELETE',
        schema: 'public',
        table: 'chat_threads'
      }, (payload) => {
        setThreads(prev => prev.filter(th => th.id !== payload.old.id));
      })
      .subscribe();

    return () => {
      if (matchDebounceTimer) clearTimeout(matchDebounceTimer);
      supabase.removeChannel(chatChannel);
    };
  }, [user, fetchThreads, sessionReady]);
  const markRead = useCallback((chatId: string) => {
    setUnreadMap(prev => {
      const next = { ...prev, [chatId]: 0 };
      try { localStorage.setItem('migo_unread_map', JSON.stringify(next)); } catch {}
      return next;
    });
    setThreads(prev => prev.map(th => th.id === chatId ? {
      ...th,
      unread: 0
    } : th));
  }, []);
  const addUnread = useCallback((chatId: string, count = 1) => {
    setUnreadMap(prev => {
      const next = { ...prev, [chatId]: (prev[chatId] ?? 0) + count };
      try { localStorage.setItem('migo_unread_map', JSON.stringify(next)); } catch {}
      return next;
    });
  }, []);
  const resetAll = useCallback(() => {
    setUnreadMap({});
    try { localStorage.setItem('migo_unread_map', '{}'); } catch {}
  }, []);
  const createGroupThread = useCallback((group: {
    id: string;
    title: string;
    hostPhoto: string;
    memberPhotos: string[];
    currentMembers: number;
    destination: string;
  }): string => {
    // 비동기로 DB에 그룹 chat_thread 생성 + 자신을 멤버로 추가
    (async () => {
      if (!user) return;
      const { data: thread } = await supabase.from('chat_threads').insert({
        name: group.title || i18n.t("auto.g_0320", "Group Chat"),
        is_group: true,
        photo_url: group.hostPhoto
      }).select('id').single();
      if (thread) {
        // 🚨 [CRITICAL SECURITY WARNING] 채팅방 하이재킹(Chat Hijacking) 취약점 구간
        // 클라이언트에서 직접 'chat_members' 테이블에 자신의 user_id를 Insert하고 있습니다.
        // 현재 DB RLS 정책이 단순히 "자기 자신(auth.uid = user_id)은 인서트 가능"으로 되어 있다면, 
        // 악의적 사용자가 타인의 비밀 thread_id만 알아내어 이 API를 호출함으로써 원격으로 
        // 1:1 채팅방에 몰래 잠입(Join)하여 모든 대화 내용을 엿볼 수 있는 심각한 위험이 존재합니다.
        // TODO: 채팅방 생성 및 멤버 초대는 반드시 서버(Edge Function/RPC)를 거쳐서
        // 권한이 있는 자만 추가되도록 DB 구조를 리팩토링해야 합니다.
        await supabase.from('chat_members').upsert(
          { thread_id: thread.id, user_id: user.id },
          { onConflict: 'thread_id,user_id' }
        );
        fetchThreads();
      }
    })();
    return group.id;
  }, [fetchThreads, user]);
  return <ChatContext.Provider value={{
    totalUnread,
    threads,
    markRead,
    addUnread,
    resetAll,
    setOpenThread: handleSetOpenThread,
    createGroupThread
  }}>
      {children}
    </ChatContext.Provider>;
};

import React, { createContext, useContext, useState, useCallback } from "react";

// ──────────────────────────────────────────────
// Types
// ──────────────────────────────────────────────
export type Destination = string | null;


export interface DateRange {
  start: string | null; // ISO date string "YYYY-MM-DD"
  end: string | null;
}

export interface GlobalFilterState {
  destination: Destination;
  dateRange: DateRange;
  groupSize: number | null; // null = any
}

interface GlobalFilterContextValue {
  filters: GlobalFilterState;
  setDestination: (d: Destination) => void;
  setDateRange: (r: DateRange) => void;
  setGroupSize: (n: number | null) => void;
  resetFilters: () => void;
  activeCount: number; // how many filters are active
}

// ──────────────────────────────────────────────
// Default state
// ──────────────────────────────────────────────
const DEFAULT_FILTERS: GlobalFilterState = {
  destination: null,
  dateRange: { start: null, end: null },
  groupSize: null,
};

// ──────────────────────────────────────────────
// Context
// ──────────────────────────────────────────────
const GlobalFilterContext = createContext<GlobalFilterContextValue | undefined>(undefined);

export const GlobalFilterProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [filters, setFilters] = useState<GlobalFilterState>(DEFAULT_FILTERS);

  const setDestination = useCallback((d: Destination) => {
    setFilters((prev) => ({ ...prev, destination: d }));
  }, []);

  const setDateRange = useCallback((r: DateRange) => {
    setFilters((prev) => ({ ...prev, dateRange: r }));
  }, []);

  const setGroupSize = useCallback((n: number | null) => {
    setFilters((prev) => ({ ...prev, groupSize: n }));
  }, []);

  const resetFilters = useCallback(() => {
    setFilters(DEFAULT_FILTERS);
  }, []);

  const activeCount =
    (filters.destination ? 1 : 0) +
    (filters.dateRange.start || filters.dateRange.end ? 1 : 0) +
    (filters.groupSize !== null ? 1 : 0);

  return (
    <GlobalFilterContext.Provider
      value={{ filters, setDestination, setDateRange, setGroupSize, resetFilters, activeCount }}
    >
      {children}
    </GlobalFilterContext.Provider>
  );
};

export const useGlobalFilter = (): GlobalFilterContextValue => {
  const ctx = useContext(GlobalFilterContext);
  if (!ctx) throw new Error("useGlobalFilter must be used within GlobalFilterProvider");
  return ctx;
};

import i18n from "@/i18n";
import {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef,
  ReactNode,
} from "react";
import { supabase } from "@/lib/supabaseClient";
import { useAuth } from "@/hooks/useAuth";

export type NotifType =
  | "profile_view"
  | "like"
  | "superlike"
  | "comment"
  | "match"
  | "group_join"
  | "group_approved"
  | "group_rejected"
  | "message"
  | string;

export interface Notif {
  id: string;
  type: NotifType;
  actorId: string;
  actor: string;
  actorPhoto: string;
  target?: string;
  time: string;
  read: boolean;
}

/** 새 메시지 인앱 배너용 */
export interface MessageBanner {
  threadId: string;
  senderName: string;
  senderPhoto: string;
  preview: string;
}

interface NotificationContextType {
  notifs: Notif[];
  unreadCount: number;
  markRead: (id: string) => void;
  markAllRead: () => void;
  addNotif: (n: Omit<Notif, "id" | "time" | "read">) => void;
  /** 채팅 메시지 수신 배너 (null = 숨김) */
  messageBanner: MessageBanner | null;
  clearMessageBanner: () => void;
}

const NotificationContext = createContext<NotificationContextType>({
  notifs: [],
  unreadCount: 0,
  markRead: () => {},
  markAllRead: () => {},
  addNotif: () => {},
  messageBanner: null,
  clearMessageBanner: () => {},
});

export const useNotifications = () => useContext(NotificationContext);

/** 상대적 timestamp (방금 전, 5분 전, …) */
function formatTime(isoStr: string): string {
  const diffSec = Math.floor((Date.now() - new Date(isoStr).getTime()) / 1000);
  if (diffSec < 60) return i18n.t("notif.justNow", "방금 전");
  if (diffSec < 3600) return i18n.t("notif.minutesAgo", { count: Math.floor(diffSec / 60), defaultValue: `${Math.floor(diffSec / 60)}분 전` });
  return new Intl.DateTimeFormat(i18n.language || "en", {
    hour: "numeric",
    minute: "numeric",
  }).format(new Date(isoStr));
}

export const NotificationProvider = ({ children }: { children: ReactNode }) => {
  const { user, sessionReady } = useAuth();

  // ── 로컬 읽음 캐시 (DB 실패 시에도 UI 반영 유지) ──
  const [readIds, setReadIds] = useState<Set<string>>(() => {
    try {
      const stored = localStorage.getItem("readNotifs");
      return new Set<string>(stored ? JSON.parse(stored) : []);
    } catch {
      return new Set<string>();
    }
  });
  const readIdsRef = useRef(readIds);
  useEffect(() => { readIdsRef.current = readIds; }, [readIds]);

  const [notifs, setNotifs] = useState<Notif[]>([]);
  const [messageBanner, setMessageBanner] = useState<MessageBanner | null>(null);

  const unreadCount = notifs.filter((n) => !n.read && !readIds.has(n.id)).length;

  // ── 알림 목록 fetch ──
  useEffect(() => {
    if (!user || !sessionReady) return;

    const fetchNotifs = async () => {
      const { data, error } = await supabase
        .from("notifications")
        .select("id, type, actor_id, target_text, is_read, created_at")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false })
        .limit(50);

      if (!error && data && data.length > 0) {
        const actorIds = [
          ...new Set(data.map((n: any) => n.actor_id).filter(Boolean)),
        ];
        const { data: actorProfiles } = await supabase
          .from("profiles")
          .select("id, name, photo_url")
          .in("id", actorIds);

        const profileMap: Record<string, any> = {};
        for (const p of actorProfiles || []) profileMap[p.id] = p;

        setNotifs(
          data.map((n: any) => ({
            id: n.id,
            type: n.type,
            actorId: n.actor_id,
            actor:
              profileMap[n.actor_id]?.name ||
              i18n.t("auto.g_0321", "Anonymous"),
            actorPhoto: profileMap[n.actor_id]?.photo_url || "",
            target: n.target_text || undefined,
            time: formatTime(n.created_at),
            read: (n.is_read ?? false) || readIdsRef.current.has(n.id),
          }))
        );
      }
    };

    fetchNotifs();

    // ── 단일 채널: notifications + in_app_notifications + messages ──
    const channel = supabase
      .channel(`notifs_all:${user.id}`)

      // 1) notifications 테이블 (좋아요 / 매칭 / 댓글 / 그룹)
      .on(
        "postgres_changes",
        {
          event: "INSERT",
          schema: "public",
          table: "notifications",
          filter: `user_id=eq.${user.id}`,
        },
        async (payload) => {
          const n = payload.new as any;
          const { data: actorProfile } = await supabase
            .from("profiles")
            .select("name, photo_url")
            .eq("id", n.actor_id)
            .single();

          setNotifs((prev) => [
            {
              id: n.id,
              type: n.type,
              actorId: n.actor_id,
              actor:
                actorProfile?.name || i18n.t("auto.g_0322", "Anonymous"),
              actorPhoto: actorProfile?.photo_url || "",
              target: n.target_text || undefined,
              time: formatTime(n.created_at),
              read:
                (n.is_read ?? false) || readIdsRef.current.has(n.id),
            },
            ...prev,
          ]);
        }
      )

      // 2) in_app_notifications (관리자 발송 / 시스템)
      .on(
        "postgres_changes",
        {
          event: "INSERT",
          schema: "public",
          table: "in_app_notifications",
          filter: `user_id=eq.${user.id}`,
        },
        (payload) => {
          const n = payload.new as any;
          setNotifs((prev) => [
            {
              id: n.id,
              type: n.type || "comment",
              actorId: "",
              actor: "",
              actorPhoto: "",
              target: n.message || n.content || undefined,
              time: formatTime(n.created_at || new Date().toISOString()),
              read: false,
            },
            ...prev,
          ]);
        }
      )

      // 3) messages (새 채팅 메시지 → 인앱 배너)
      .on(
        "postgres_changes",
        {
          event: "INSERT",
          schema: "public",
          table: "messages",
        },
        async (payload) => {
          const msg = payload.new as any;
          if (!msg.sender_id || msg.sender_id === user.id) return;

          // 내가 속한 채팅방인지 확인
          const { data: memberCheck } = await supabase
            .from("chat_members")
            .select("id")
            .eq("thread_id", msg.thread_id)
            .eq("user_id", user.id)
            .maybeSingle();

          if (!memberCheck) return;

          // 발신자 정보 조회
          const { data: sender } = await supabase
            .from("profiles")
            .select("name, photo_url")
            .eq("id", msg.sender_id)
            .single();

          const rawText = msg.text || msg.content || "";
          const preview =
            rawText.length > 50
              ? rawText.slice(0, 50) + "…"
              : rawText || i18n.t("notif.newMessage", "새 메시지");

          setMessageBanner({
            threadId: msg.thread_id,
            senderName: sender?.name || i18n.t("auto.g_0321", "Anonymous"),
            senderPhoto: sender?.photo_url || "",
            preview,
          });

          // 4초 후 자동 닫기
          setTimeout(() => setMessageBanner(null), 4000);
        }
      )

      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id, sessionReady]);

  // ── 읽음 처리 (notifications + in_app_notifications 모두) ──
  const markRead = useCallback(
    async (id: string) => {
      setReadIds((prev) => {
        const next = new Set(prev);
        next.add(id);
        localStorage.setItem("readNotifs", JSON.stringify([...next]));
        return next;
      });
      setNotifs((prev) =>
        prev.map((n) => (n.id === id ? { ...n, read: true } : n))
      );
      // 두 테이블 모두 업데이트 (어느 쪽 테이블 레코드인지 모르므로 양쪽 시도)
      await Promise.allSettled([
        supabase.from("notifications").update({ is_read: true }).eq("id", id),
        supabase
          .from("in_app_notifications")
          .update({ is_read: true })
          .eq("id", id),
      ]);
    },
    []
  );

  // ── 전체 읽음 처리 ──
  const markAllRead = useCallback(
    async () => {
      if (!user) return;

      setNotifs((prev) => {
        const allIds = prev.map((n) => n.id);
        setReadIds((prevIds) => {
          const next = new Set(prevIds);
          allIds.forEach((id) => next.add(id));
          localStorage.setItem("readNotifs", JSON.stringify([...next]));
          return next;
        });
        return prev.map((n) => ({ ...n, read: true }));
      });

      await Promise.allSettled([
        supabase
          .from("notifications")
          .update({ is_read: true })
          .eq("user_id", user.id),
        supabase
          .from("in_app_notifications")
          .update({ is_read: true })
          .eq("user_id", user.id),
      ]);
    },
    [user?.id]
  );

  // ── 직접 알림 추가 (UI 레벨에서 필요한 경우) ──
  const addNotif = useCallback(
    async (template: Omit<Notif, "id" | "time" | "read">) => {
      if (!user) return;
      await supabase.from("notifications").insert({
        user_id: user.id,
        type: template.type,
        actor_id: user.id,
        target_text: template.target,
      });
    },
    [user]
  );

  const clearMessageBanner = useCallback(() => setMessageBanner(null), []);

  return (
    <NotificationContext.Provider
      value={{
        notifs,
        unreadCount,
        markRead,
        markAllRead,
        addNotif,
        messageBanner,
        clearMessageBanner,
      }}
    >
      {children}
    </NotificationContext.Provider>
  );
};

import { createContext, useContext, useState, useCallback, useEffect, useRef, ReactNode } from "react";
import { supabase } from "@/lib/supabaseClient";
import { useAuth } from "@/hooks/useAuth";
import {
  purchaseSubscription as iapPurchaseSubscription,
  purchaseConsumable as iapPurchaseConsumable,
