  .use(
    resourcesToBackend(async (language: string, namespace: string) => {
      // json 파일을 동적으로 import (vite의 import() 사용 시 빌드타임에서 파일을 자동으로 분할합니다)
      const res = await import(`./locales/${language}.ts`);

