      const FILTER = (FILTER_LOCALES as any)[language] || {};
      const CHECKIN = (CHECKIN_LOCALES as any)[language] || {};
      const TIER = (TIER_LOCALES as any)[language] || {};
      const GDF = (GDF_LOCALES as any)[language] || {};
