export async function toggleAdSlot(id: string, enabled: boolean): Promise<boolean> {
  if (!isSupabaseConfigured) {
    const slot = MOCK_AD_SLOTS.find(s => s.id === id);
    if (slot) slot.enabled = enabled;
    return true;
  }
  const {
    error
