    enabled
  }).eq("id", id);
  if (error) {
    console.error("toggleAdSlot error:", error);
    return false;
  }
  return true;
}

/** 이미지를 Supabase Storage에 업로드 */
export async function uploadAdImage(file: File): Promise<string | null> {
  if (!isSupabaseConfigured) {
    // ⚠️ Mock 모드: Object URL은 콨포넌트 언마운트 시 URL.revokeObjectURL(url)로 반드시 정리해야 함 (메모리 누수)
    return URL.createObjectURL(file);
  }
  const compressedFile = await compressImage(file);
  const ext = compressedFile.name.split(".").pop();
  const uuidPrefix = (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID().split('-')[0] : Array.from(crypto.getRandomValues(new Uint8Array(4))).map(b => b.toString(16).padStart(2, '0')).join('');
  const path = `ads/${Date.now()}-${uuidPrefix}.${ext}`;
  const {
    error
  } = await supabase.storage.from("ad-images").upload(path, compressedFile, {
    upsert: true,
    contentType: compressedFile.type
  });
  if (error) {
    console.error("uploadAdImage error:", error);
    return null;
  }
  const {
    data
  } = supabase.storage.from("ad-images").getPublicUrl(path);
  return data.publicUrl;
}

/** 클릭 기록 */
export async function recordAdClick(adId: string, userId: string | null): Promise<void> {
  if (!isSupabaseConfigured) return;
  await supabase.from("ad_clicks").insert({
    ad_id: adId,
    user_id: userId
  });
  // 원자적 클릭수 증가 (RPC 사용 권장)
  await supabase.rpc("increment_ad_clicks", { row_id: adId }).then(({ error }) => {
    if (error) {
      // RPC 없을 경우 fallback: 원자적 SQL 증가 (select→update race condition 방지)
      supabase.from("ads").update({ clicks: supabase.rpc ? undefined : 0 } as any)
        .eq("id", adId);
      // PostgREST는 직접 increment를 지원하지 않으므로, raw SQL RPC가 없으면
      // ad_clicks 테이블의 count(*)로 동기화하는 방식 사용
      supabase.from("ad_clicks").select("id", { count: 'exact', head: true })
        .eq("ad_id", adId)
        .then(({ count }) => {
          if (count !== null) {
            supabase.from("ads").update({ clicks: count }).eq("id", adId);
          }
        });
    }
  });
}

/** 노출 기록 */
export async function recordAdImpression(adId: string, userId: string | null): Promise<void> {
  if (!isSupabaseConfigured) return;
  await supabase.from("ad_impressions").insert({
    ad_id: adId,
    user_id: userId
  });
  await supabase.rpc("increment_ad_impressions", { row_id: adId }).then(({ error }) => {
    if (error) {
      // RPC 없을 경우 fallback: ad_impressions count로 동기화 (race condition 방지)
      supabase.from("ad_impressions").select("id", { count: 'exact', head: true })
        .eq("ad_id", adId)
        .then(({ count }) => {
          if (count !== null) {
            supabase.from("ads").update({ impressions: count }).eq("id", adId);
          }
        });
    }
  });
}

/** 특정 앱 화면에 맞는 활성 광고 가져오기 (게재중, 예산 남음, 기간 내) */
export async function fetchActiveAdsForScreen(appScreen: string): Promise<any[]> {
  if (!isSupabaseConfigured) return [];

  // 10분 캐시 — 광고 데이터는 실시간성 불필요, 트래픽 절감
  const CACHE_KEY = `ads:screen:${appScreen}`;
  const cached = getCached<any[]>(CACHE_KEY);
  if (cached) return cached;

  const today = new Date().toISOString().split("T")[0];

  // 1) Get the enabled slots for this screen
  const {
    data: slots,
    error: slotErr
  } = await supabase.from("ad_slots").select("id, format, dimensions, max_active").eq("enabled", true).eq("app_screen", appScreen);
  if (slotErr || !slots || slots.length === 0) return [];
  const slotIds = slots.map(s => s.id);

  // 2) Get active ads — only rendering-relevant columns (no analytics, no budget internals)
  const {
    data: ads,
    error: adErr
  } = await supabase
    .from("ads")
    .select("id, title, advertiser, slot_id, image_url, cta_url, cta_text, headline, body_text, budget, budget_spent, status, start_date, end_date")
    .eq("status", "active")
    .in("slot_id", slotIds)
    .lte("start_date", today)
    .gte("end_date", today);
  if (adErr || !ads) return [];

  // 3) Filter budget in memory and map format
  const validAds = (ads as any[]).filter(a => a.budget_spent < a.budget);

  const result = validAds.map(a => {
    const s = slots.find(x => x.id === a.slot_id);
    return {
      ...a,
      format: s?.format,
      max_active: s?.max_active
    };
  });

  setCache(CACHE_KEY, result, 10 * 60 * 1000); // 10분 캐시
  return result;
}

