// ── 네이티브 환경 체크 —————————————————————
// iOS: StoreKit, Android: Google Play Billing (→ @capgo/native-purchases 자동 선택)
export const isNativePlatform = (): boolean => {
  return Capacitor.isNativePlatform();
};

/** @deprecated 구 iOS 전용 체크 — 이제 isNativePlatform() 사용 */
export const isNativeIOS = (): boolean => {
  return Capacitor.isNativePlatform() && Capacitor.getPlatform() === 'ios';
};

export const isAndroid = (): boolean => {
  return Capacitor.isNativePlatform() && Capacitor.getPlatform() === 'android';
};

// ── 결제 지원 여부 확인 ──────────────────────────────
export const checkBillingSupported = async (): Promise<boolean> => {
  // iOS: StoreKit, Android: Google Play Billing 둘 다 지원
  if (!isNativePlatform()) return false;
  try {
    const { isBillingSupported } = await NativePurchases.isBillingSupported();
    return isBillingSupported;
  } catch {
    return false;
  }
};

// ── 상품 정보 조회 ───────────────────────────────────
export const getIAPProducts = async (productIds: string[], isSubscription = true) => {
  if (!isNativePlatform()) return [];  // iOS + Android 모두 지원
  try {
    const { products } = await NativePurchases.getProducts({
      productIdentifiers: productIds,
      productType: isSubscription ? PURCHASE_TYPE.SUBS : PURCHASE_TYPE.INAPP,
    });
    return products;
  } catch (e) {
    console.warn('[IAP] getProducts error:', e);
    return [];
  }
};

// ── 구독 상품 구매 ───────────────────────────────────────────
export interface PurchaseResult {
  success: boolean;
  transactionId?: string;
  error?: string;
  cancelled?: boolean;
}

export const purchaseSubscription = async (productId: IAPProductId): Promise<PurchaseResult> => {
  if (!isNativePlatform()) {
    return { success: false, error: 'not_native' };
  }
  // Note: @capgo/native-purchases v6 uses StoreKit 2 directly — no setup() call needed.
  // purchaseProduct() first calls Product.products(for: [id]); if empty it rejects
  // with "Cannot find product for id ...". This typically means the product is not
  // in "Ready to Submit" status in App Store Connect, or the Paid Apps Agreement
  // is not active. We surface this as a distinct error code.
  try {
    const transaction = await NativePurchases.purchaseProduct({
      productIdentifier: productId,
      productType: PURCHASE_TYPE.SUBS,
    });
    return { success: true, transactionId: String(transaction.transactionId) };
  } catch (e: any) {
    const message = e?.message || String(e);
    if (message.includes('cancel') || message.includes('Cancel') || e?.code === 2) {
      return { success: false, cancelled: true };
    }
    // StoreKit 2 returns this when App Store Connect product is not found/ready
    const isProductNotFound = message.includes('Cannot find product') || message.includes('invalid product');
    console.warn('[IAP] purchaseSubscription failed:', isProductNotFound ? 'product_not_found' : 'store_error');
    return {
      success: false,
      error: isProductNotFound ? 'product_not_found' : message,
    };
  }
};

// ── 소비성 아이템 구매 ───────────────────────────────────────
export const purchaseConsumable = async (productId: IAPProductId): Promise<PurchaseResult> => {
  if (!isNativePlatform()) {
    return { success: false, error: 'not_native' };
  }
  try {
    const transaction = await NativePurchases.purchaseProduct({
      productIdentifier: productId,
      productType: PURCHASE_TYPE.INAPP,
    });
    return { success: true, transactionId: String(transaction.transactionId) };
  } catch (e: any) {
    const message = e?.message || String(e);
    if (message.includes('cancel') || message.includes('Cancel') || e?.code === 2) {
      return { success: false, cancelled: true };
    }
    const isProductNotFound = message.includes('Cannot find product') || message.includes('invalid product');
    console.warn('[IAP] purchaseConsumable failed:', isProductNotFound ? 'product_not_found' : 'store_error');
    return {
      success: false,
      error: isProductNotFound ? 'product_not_found' : message,
    };
  }
};

// ── 구매 복원 ────────────────────────────────────────────────
export const restoreIAPPurchases = async (): Promise<{
  restored: boolean;
  activeSubscriptions: string[];
  error?: string;
}> => {
  if (!isNativePlatform()) {
    return { restored: false, activeSubscriptions: [], error: 'not_native' };
  }
  try {
    const { customerInfo } = await NativePurchases.restorePurchases();
    return {
      restored: true,
      activeSubscriptions: customerInfo.activeSubscriptions as unknown as string[],
    };
  } catch (e: any) {
    // 에러 메시지를 외부에 노출하지 않고 오류 코드만 전달
    console.warn('[IAP] restorePurchases failed');
    return { restored: false, activeSubscriptions: [], error: 'restore_failed' };
  }
};

// ── productId → 플랜 타입 ────────────────────────────────────
export const getSubscriptionPlanFromProductId = (productId: string): 'plus' | 'premium' | null => {
  if (productId === IAP_PRODUCT_IDS.PREMIUM_MONTHLY) return 'premium';
  if (([
    IAP_PRODUCT_IDS.PLUS_MONTHLY,
    IAP_PRODUCT_IDS.PLUS_QUARTERLY,
    IAP_PRODUCT_IDS.PLUS_YEARLY,
  ] as string[]).includes(productId)) return 'plus';
  return null;
};

import { Geolocation, Position } from '@capacitor/geolocation';
import { Capacitor } from '@capacitor/core';
import { toast } from '@/hooks/use-toast';
import i18n from '@/i18n';

export interface GeoLocationResult {
  lat: number;
  lng: number;
}

/**
 * getCurrentLocation
 * A unified robust GPS location fetcher utilizing Capacitor's exact native OS API.
 * Guarantees maximum active accuracy (`enableHighAccuracy: true`) and prevents 
 * permissions loops natively by verifying OS permissions.
 */
export const getCurrentLocation = async (showToastOnFail = false): Promise<GeoLocationResult | null> => {
  try {
    if (Capacitor.isNativePlatform()) {
      let permStatus = await Geolocation.checkPermissions();
      if (permStatus.location !== 'granted') {
        permStatus = await Geolocation.requestPermissions();
        if (permStatus.location !== 'granted') {
          if (showToastOnFail) {
            toast({ title: i18n.t("alert.t23Title", "위치 권한이 필요해요"), variant: "destructive" });
          }
          return null;
        }
      }
    } else {
      // 웹: navigator.geolocation 지원 여부 확인
      if (!navigator.geolocation) {
        return null;
      }
      // 웹: Permissions API로 이미 거부됐으면 요청 없이 null 반환
      try {
        const perm = await navigator.permissions.query({ name: 'geolocation' });
        if (perm.state === 'denied') {
          // 사용자가 이미 거부한 상태 — 조용히 null 반환
          return null;
        }
      } catch {
        // Permissions API 미지원 브라우저는 그냥 진행
      }
    }

    const position: Position = await Geolocation.getCurrentPosition({
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 30000, // 30초 캐시 허용 (전력 절감)
    });

    return {
      lat: position.coords.latitude,
      lng: position.coords.longitude,
    };
  } catch (error: any) {
    // code 1 = PERMISSION_DENIED (사용자가 의도적으로 거부) — 에러가 아닌 정상 동작
    if (error?.code === 1 || error?.message?.toLowerCase().includes('denied')) {
      return null;
    }
    // 나머지 에러 (타임아웃 등)만 로그
    console.warn(i18n.t("auto.g_0356", "[GPS] 위치 가져오기 실패:"), error?.message || error);
    if (showToastOnFail) {
      toast({
        title: i18n.t("auto.z_위치권한이필요합니다_1453", "위치를 가져올 수 없습니다."),
        description: i18n.t("auto.g_0047_loc", "잠시 후 다시 시도해주세요."),
        variant: "destructive",
      });
    }
    return null;
  }
};

import i18n from "@/i18n";
import { supabase } from "./supabaseClient";
export interface Package {
  id: string;
  title: string;
  host: string;
  hostAvatar: string;
  destination: string;
  category: "tour" | "stay" | "activity" | "food" | string;
  price: number;
  duration: string;
  maxPeople: number;
  currentPeople: number;
  rating: number;
  reviewCount: number;
  image: string;
  tags: string[];
  description: string;
  featured?: boolean;
}

// Helper to standardise fetched data
const mapToPackage = (d: any): Package => ({
  id: d.id,
  title: d.title || i18n.t("auto.g_0357", "무제"),
  host: d.profiles?.name || d.host || i18n.t("auto.g_0358", "익명호스트"),
  hostAvatar: d.profiles?.photo_url || d.host_avatar || "https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?w=100&q=80",
  destination: d.destination || i18n.t("auto.g_0359", "미등록"),
  category: d.category || 'tour',
  price: d.price || 0,
  duration: d.duration || i18n.t("auto.g_0360", "상세보기9"),
  maxPeople: d.max_people || 10,
  currentPeople: d.current_people || 0,
  rating: d.rating || 0,
  reviewCount: d.review_count || 0,
  image: d.image_url || "https://images.unsplash.com/photo-1528360983277-13d401cdc186?w=400&q=80",
  tags: d.tags || [],
  description: d.description || '',
  featured: d.featured || false
});

/** 상품 목록 조회 — 항상 실제 DB */
export async function fetchMarketplaceItems(): Promise<Package[]> {
  const {
    data,
    error
  } = await supabase.from('marketplace_items').select('*, profiles (name, photo_url)').order("created_at", {
    ascending: false
  });
  if (error) {
    console.warn("fetchMarketplaceItems error:", error.message);
    return [];
  }
  return (data || []).map(mapToPackage);
}

/** 상품 등록 — 항상 실제 DB */
export async function createMarketplaceItem(item: Omit<Package, "id" | "host" | "hostAvatar" | "rating" | "reviewCount">) {
  // 현재 로그인한 유저의 ID를 host_id로 사용
  const {
    data: {
      user
    }
  } = await supabase.auth.getUser();
  const payload = {
    host_id: user?.id ?? null,
    title: item.title,
    destination: item.destination,
    category: item.category,
    price: item.price,
    duration: item.duration,
    max_people: item.maxPeople,
    current_people: item.currentPeople,
    image_url: item.image,
    tags: item.tags,
    description: item.description,
    featured: item.featured ?? false
  };
  const {
    error
  } = await supabase.from("marketplace_items").insert(payload);
  if (error) {
    console.error("createMarketplaceItem error:", error.message);
    return false;
  }
  return true;
}

/** 상품 수정 — 항상 실제 DB */
export async function updateMarketplaceItem(id: string, updates: Partial<Package>) {
  const payload: any = {};
  if (updates.title !== undefined) payload.title = updates.title;
  if (updates.description !== undefined) payload.description = updates.description;
  if (updates.price !== undefined) payload.price = updates.price;
  if (updates.image !== undefined) payload.image_url = updates.image;
  if (updates.featured !== undefined) payload.featured = updates.featured;
  if (updates.category !== undefined) payload.category = updates.category;
  if (updates.destination !== undefined) payload.destination = updates.destination;
  if (updates.duration !== undefined) payload.duration = updates.duration;
  if (updates.maxPeople !== undefined) payload.max_people = updates.maxPeople;
  if (updates.tags !== undefined) payload.tags = updates.tags;
  const {
    error
  } = await supabase.from("marketplace_items").update(payload).eq("id", id);
  if (error) {
    console.error("updateMarketplaceItem error:", error.message);
    return false;
  }
  return true;
}

/** 상품 삭제 — 항상 실제 DB */
export async function deleteMarketplaceItem(id: string) {
  const {
    error
  } = await supabase.from("marketplace_items").delete().eq("id", id);
  if (error) {
    console.error("deleteMarketplaceItem error:", error.message);
    return false;
  }
  return true;
}

import i18n from "@/i18n";

export type CountryTier = 1 | 2 | 3;

const TIER_1_COUNTRIES = [
  "KR", "US", "JP", "GB", "AU", "CA", "NZ", "CH", "SG", "TW", "HK", "AE", "SA", "QA",
  "DE", "FR", "IT", "ES", "NL", "SE", "NO", "FI", "DK", "IE", "AT", "BE", "LU"
];
const TIER_2_COUNTRIES = [
  "BR", "MX", "AR", "CO", "CL", "PE", "TR", "RU", "PL", "CZ", "HU", "RO", "GR", "PT",
  "ZA", "EG", "MA"
];
// Default everything else to Tier 3

const COUNTRY_CURRENCIES: Record<string, string> = {
  KR: "KRW",
  JP: "JPY",
  GB: "GBP",
  EU: "EUR", // Fallback for Eurozone
  DE: "EUR", FR: "EUR", IT: "EUR", ES: "EUR", NL: "EUR", AT: "EUR", IE: "EUR", BE: "EUR", FI: "EUR", LU: "EUR",
  AU: "AUD",
  CA: "CAD",
  SG: "SGD",
  CH: "CHF"
};

const getCountryCode = (): string => {
  // Try to extract from currently selected language (e.g. ko-KR -> KR, en-US -> US)
  // Or fallback to checking browser timezone or navigator language
  const navLang = i18n.language || navigator.language || "en-US";
  const parts = navLang.split('-');
  if (parts.length > 1) {
    return parts[1].toUpperCase();
  }

  // Map 2-letter language codes to default country codes for pricing tier mapping
  const langToCountry: Record<string, string> = {
    ko: "KR",
    ja: "JP",
    zh: "TW",
    en: "US",
    fr: "FR",
    de: "DE",
    es: "ES",
    it: "IT",
    pt: "BR",
    id: "ID",
    th: "TH",
    vi: "VN",
    ru: "RU",
    tr: "TR"
  };
  return langToCountry[navLang] || "US";
};

const getTier = (countryCode: string): CountryTier => {
  if (TIER_1_COUNTRIES.includes(countryCode)) return 1;
  if (TIER_2_COUNTRIES.includes(countryCode)) return 2;
  return 3;
};

// Premium Subscription Pricing
export const getMigoPlusPricing = () => {
  const country = getCountryCode();
  const tier = getTier(country);
  const currency = COUNTRY_CURRENCIES[country] || "USD";

  /**
 * ══════════════════════════════════════════════════════
 * MIGO 수익 모델 (순이익 공식 반영 가격)
 * ══════════════════════════════════════════════════════
 * 순이익 = 결제금액 - 앱스토어수수료(15%) - 운영비 - UAC상각
 *
 * 비용 상수:
 *  앱스토어: 15% (Apple/Google 소규모 사업자)
 *  광고 예산: Phase1 ₩500,000/월 → Phase2 ₩1,000,000 → Phase3 ₩2,000,000
 *  예상 CPI: ₩1,884 (Meta 50% + TikTok 30% + Google UAC 20%)
 *  월 신규 설치: 265건 (Phase1)
 *  유료 전환율: 8% → 21명/월
 *  블렌디드 CAC: ₩15,748 (유기 설치 포함)
 *  UAC 상각: ₩15,748 ÷ 8개월 = ₩2,000/월  [이전 ₩5,000 → 수정]
 *  운영비 Plus: ₩1,813/월 (Maps ₩1,200 + AI ₩80 + Infra ₩533)
 *  운영비 Premium: ₩2,813/월
 *
 * 플랜별 검증 (수정된 UAC 반영):
 *  Plus 월간  ₩14,900 → 순이익 ₩8,852  (59.4%) ✅✅
 *  Plus 3개월 ₩34,900 → 순이익 ₩18,226 (52.2%) ✅✅
 *  Plus 연간  ₩99,900 → 순이익 ₩47,411 (47.5%) ✅✅
 *
 * BEP: Phase1 광고비 기준 Month 5 달성 (유료 유저 78명)
 */
  if (currency === "KRW") {
    return {
      currency: "₩",
      month1: 14900,
      month3: 34900,   // ₩28,900 → ₩34,900 (UAC+운영비 반영)
      month12: 99900,  // ₩79,900 → ₩99,900 (연간 UAC 총비용 반영)
      format: (val: number) => `₩${val.toLocaleString()}`
    };
  }

  // USD prices by tier (net margin validated)
  const pricesUSD = {
    1: { month1: 11.99, month3: 26.99, month12: 74.99 },
    2: { month1: 7.99,  month3: 17.99, month12: 49.99 },
    3: { month1: 4.99,  month3: 10.99, month12: 29.99 }
  };

  const p = pricesUSD[tier];

  return {
    currency: "$",
    month1: p.month1,
    month3: p.month3,
    month12: p.month12,
    format: (val: number) => `$${val.toFixed(2)}`
  };
};

