const _projectRef = isSupabaseConfigured
  ? new URL(supabaseUrl).hostname.split(".")[0]
  : "";
const _sessionKey = `sb-${_projectRef}-auth-token`;

function _readSessionFromStorage() {
  try {
    const raw = localStorage.getItem(_sessionKey);
