         const lng = p.location?.lng || p.lng;
         if (lat && lng) {
           const d = calcDist(myLatLngRef.current!.lat, myLatLngRef.current!.lng, lat, lng);
           if (d < minDist) { minDist = d; nearest = p; }
         }
      });
      if (nearest && minDist < 9999) {
