                      </div>
                      <div className="absolute -bottom-1.5 left-1/2 -translate-x-1/2 w-3 h-3 bg-white rotate-45 transform origin-center border-b-2 border-r-2 border-transparent shadow-sm" />
                      {isSelected && (
