import i18n from "@/i18n";
import { useTranslation } from "react-i18next";
import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { getLocalizedPrice } from "@/lib/pricing";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, Star, MapPin, Clock, Users, Tag, X, ChevronRight, Sparkles, Heart, Award, Check } from "lucide-react";
import { toast } from "@/hooks/use-toast";
import { supabase } from "@/lib/supabaseClient";
import { useAuth } from "@/hooks/useAuth";
import PaymentModal from "@/components/PaymentModal";
import { fetchMarketplaceItems, Package } from "@/lib/marketplaceService";

// ─── Categories ────────────────────────────────────
const CATEGORIES = [
  { id: "all", labelKey: "marketplace.all", emoji: "🌏" },
  { id: "tour", label: "Tour", emoji: "🗺️" },
  { id: "activity", labelKey: "marketplace.activity", emoji: "🏄" },
  { id: "food", labelKey: "marketplace.food", emoji: "🍜" },
  { id: "stay", labelKey: "marketplace.stay", emoji: "🏡" },
];

const CATEGORY_COLORS: Record<string, string> = {
  tour: "bg-blue-500/10 text-blue-500",
  activity: "bg-emerald-500/10 text-emerald-500",
  food: "bg-orange-500/10 text-orange-500",
  stay: "bg-purple-500/10 text-purple-500",
};

// ─── Host Registration Modal ─────────────────────────────────
const HostRegistrationModal = ({
  onClose,
  userId,
}: {
  onClose: () => void;
  userId: string;
}) => {
  const { t } = useTranslation();
  const [form, setForm] = useState({ category: "tour", intro: "", phone: "" });
  const [saving, setSaving] = useState(false);

  const handleSubmit = async () => {
    if (!form.intro || !form.phone) return;
    setSaving(true);
    const catItem = CATEGORIES.find(c => c.id === form.category);
    const catLabel = catItem?.labelKey ? i18n.t(catItem.labelKey) : (catItem?.label ?? form.category);
    // 전화번호 마스킹 저장 (평문 노우 방지)
    const maskedPhone = form.phone.length > 7
      ? form.phone.slice(0, 3) + '****' + form.phone.slice(-4)
      : '***-****-****';
    await supabase.from("reports").insert({
      reporter_id: userId,
      target_id: userId,
      type: "other", // 🚨 [Fix] DB Column Name mismatch (target_type -> type)
      reason: i18n.t("auto.t_0041", `호스트 신청\n카테고리: ${catLabel}\n연락처: ${maskedPhone}\n소개: ${form.intro}`),
    });
    setSaving(false);
    toast({
      title: i18n.t("auto.g_0043", "호스트 신청이 접수되었습니다! 🌟"),
      description: i18n.t("marketplace.hostSubmittedDesc"),
    });
    onClose();
  };

  return (
    <motion.div
      className="fixed inset-0 z-[80] flex items-center justify-center p-4"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
    >
      <div className="absolute inset-0 bg-foreground/60 backdrop-blur-sm" onClick={onClose} />
      <motion.div
        className="relative z-10 w-full max-w-sm bg-card rounded-3xl p-6 shadow-float overflow-hidden"
        initial={{ y: 20, scale: 0.95 }}
        animate={{ y: 0, scale: 1 }}
      >
        <div className="flex items-center justify-between mb-5">
          <h3 className="text-lg font-extrabold text-foreground flex items-center gap-2 truncate">
            <Award className="text-primary" size={18} />{i18n.t("auto.g_0743", "호스트 지원")}
          </h3>
          <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-xl bg-muted text-muted-foreground">
            <X size={16} />
          </button>
        </div>

        <div className="space-y-4">
          <div>
            <label className="text-xs font-bold text-muted-foreground mb-1 block">{i18n.t("auto.g_0744", "운영 카테고리")}</label>
            <div className="grid grid-cols-2 gap-2 truncate">
              {CATEGORIES.filter(c => c.id !== "all").map(c => (
                <button
                  key={c.id}
                  onClick={() => setForm(f => ({ ...f, category: c.id }))}
                  className={`py-2 rounded-xl text-xs font-bold border transition-all ${
                    form.category === c.id
                      ? "border-primary bg-primary/10 text-primary"
                      : "border-border text-muted-foreground"
                  }`}
                >
                  {c.emoji} {c.labelKey ? i18n.t(c.labelKey) : c.label}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="text-xs font-bold text-muted-foreground mb-1 block">{i18n.t("auto.g_0745", "전문 분야 및 소개")}</label>
            <textarea
              value={form.intro}
              onChange={e => setForm(f => ({ ...f, intro: e.target.value }))}
              rows={3}
              placeholder={i18n.t("auto.g_0746", "어떤 투어나 액티비티를 제공하실 건가요?")}
              className="w-full px-3 py-2.5 rounded-xl bg-muted border border-border text-sm text-foreground outline-none focus:border-primary resize-none"
            />
          </div>
          <div>
            <label className="text-xs font-bold text-muted-foreground mb-1 block">{i18n.t("auto.g_0747", "연락처")}</label>
            <input
              value={form.phone}
              onChange={e => setForm(f => ({ ...f, phone: e.target.value }))}
              placeholder="010-0000-0000"
              className="w-full px-3 py-2.5 rounded-xl bg-muted border border-border text-sm text-foreground outline-none focus:border-primary"
            />
          </div>
        </div>

        <motion.button
          whileTap={{ scale: 0.97 }}
          onClick={handleSubmit}
          disabled={saving || !form.intro || !form.phone}
          className="w-full mt-6 py-3.5 rounded-xl gradient-primary text-primary-foreground font-extrabold flex items-center justify-center gap-2 shadow-float disabled:opacity-50"
        >
          {saving ? <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /> : i18n.t("auto.g_0748", "신청서 제출")}
        </motion.button>
      </motion.div>
    </motion.div>
  );
};

// ─── BookingModal ─────────────────────────────────
interface BookingModalProps {
  pkg: Package;
  onClose: () => void;
  userId?: string;
}

const BookingModal = ({ pkg, onClose, userId }: BookingModalProps) => {
  const { t } = useTranslation();
  const [count, setCount] = useState(1);
  const [showPayment, setShowPayment] = useState(false);
  const [confirmed, setConfirmed] = useState(false);

  const handleBook = () => setShowPayment(true);

  const handlePaymentSuccess = async () => {
    if (userId) {
      const { error } = await supabase.from("reports").insert({
        reporter_id: userId,
        target_id: pkg.id,
        type: "other", // 🚨 [Fix] DB Column Name mismatch (target_type -> type)
        reason: t("auto.t_0042", `예약 신청\n상품: ${pkg.title}\n인원: ${count}명\n금액: ${getLocalizedPrice(pkg.price * count, i18n.language)}`)
      });
      if (error) {
        toast({ title: t("alert.t60Title") });
        return;
      }
    }
    setShowPayment(false);
    setConfirmed(true);
    setTimeout(() => {
      onClose();
      toast({ title: t("auto.t_0017", `${pkg.title} 예약이 완료되었습니다! 🎉`) });
    }, 1800);
  };

  if (confirmed) {
    return (
      <motion.div
        className="fixed inset-0 z-[70] flex items-center justify-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
      >
        <div className="bg-card rounded-3xl p-8 flex flex-col items-center gap-4 shadow-float">
          <div className="w-16 h-16 rounded-full bg-emerald-500/10 flex items-center justify-center">
            <Check size={32} className="text-emerald-500" />
          </div>
          <p className="text-lg font-extrabold text-foreground truncate">{t("auto.g_0749", "예약완료")}</p>
        </div>
      </motion.div>
    );
  }

  return (
    <motion.div
      className="fixed inset-0 z-[70] flex items-end justify-center px-safe pb-safe pt-safe"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
    >
      <div className="absolute inset-0 bg-foreground/60 backdrop-blur-md" onClick={onClose} />
      <motion.div
        className="relative z-10 w-full max-w-lg mx-auto bg-card rounded-3xl mb-4 sm:mb-8 shadow-float overflow-hidden"
        initial={{ y: "100%" }}
        animate={{ y: 0 }}
        exit={{ y: "100%" }}
        transition={{ type: "spring", damping: 28, stiffness: 300 }}
      >
        {/* Image strip */}
        <div className="h-36 overflow-hidden relative">
          <img src={pkg.image} alt="" className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-gradient-to-t from-card via-transparent to-transparent" />
        </div>

        <div className="p-5">
          <div className="flex items-start justify-between mb-3">
            <div>
              <h2 className="text-lg font-extrabold text-foreground">{pkg.title}</h2>
              <div className="flex items-center gap-1.5 mt-0.5">
                <MapPin size={12} className="text-muted-foreground" />
                <span className="text-xs text-muted-foreground">{pkg.destination}</span>
                <span className="text-muted-foreground/40 mx-1">·</span>
                <Clock size={12} className="text-muted-foreground" />
                <span className="text-xs text-muted-foreground">{pkg.duration}</span>
              </div>
            </div>
            <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-xl bg-muted text-muted-foreground">
              <X size={16} />
            </button>
          </div>

          {/* People selector */}
          <div className="flex items-center justify-between bg-muted rounded-2xl px-4 py-3 mb-4">
            <span className="text-sm font-bold text-foreground truncate">{t("auto.g_0750", "인원선택")}</span>
            <div className="flex items-center gap-3">
              <button
                onClick={() => setCount(c => Math.max(1, c - 1))}
                disabled={count <= 1}
                className="w-8 h-8 rounded-xl bg-card flex items-center justify-center font-bold text-foreground disabled:opacity-30"
              >
                −
              </button>
              <span className="text-base font-extrabold text-foreground w-5 text-center">{count}</span>
              <button
                onClick={() => setCount(c => Math.min(pkg.maxPeople - pkg.currentPeople, c + 1))}
                disabled={count >= pkg.maxPeople - pkg.currentPeople}
                className="w-8 h-8 rounded-xl bg-card flex items-center justify-center font-bold text-foreground disabled:opacity-30"
              >
                +
              </button>
            </div>
          </div>

          {/* Price */}
          <div className="flex items-center justify-between mb-5">
            <span className="text-sm text-muted-foreground truncate">{t("auto.g_0751", "총금액")}</span>
            <span className="text-xl font-extrabold text-foreground">{getLocalizedPrice(pkg.price * count, i18n.language)}</span>
          </div>

          <motion.button
            whileTap={{ scale: 0.97 }}
            onClick={handleBook}
            className="w-full py-4 rounded-2xl gradient-primary text-primary-foreground font-extrabold text-base shadow-float flex items-center justify-center gap-2"
          >
            {t("auto.g_0752", "예약하기")}<ChevronRight size={18} />
          </motion.button>
        </div>

        <AnimatePresence>
          {showPayment && (
            <PaymentModal
              isOpen={showPayment}
              onClose={() => setShowPayment(false)}
              groupTitle={`${pkg.title} × ${count}명`}
              groupId={pkg.id}
              onPaymentSuccess={handlePaymentSuccess}
            />
          )}
        </AnimatePresence>
      </motion.div>
    </motion.div>
  );
};

