          className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-muted text-xs font-bold text-foreground"
        >
          <Award size={13} />{t("auto.g_0758", "호스트 등록")}
        </motion.button>
      </header>

      {/* Hero banner */}
      <div
        className="mx-5 mt-3 mb-4 rounded-3xl overflow-hidden relative h-28"
        style={{ background: "linear-gradient(135deg, #6366f1 0%, #8b5cf6 50%, #f43f5e 100%)" }}
      >
        <div className="absolute inset-0 flex flex-col justify-center px-5">
          <p className="text-white/80 text-xs font-semibold truncate">{t("auto.g_0759", "Migo 마켓플레이스")}</p>
          <p className="text-white text-lg font-extrabold mt-0.5 truncate">{t("auto.g_0760", "여행 경험을 예약하세요")}</p>
          <p className="text-white/70 text-[11px] mt-0.5 truncate">{t("auto.g_0761", "예약 시 Migo 포인트 적립!")}</p>
        </div>
