      </div>}

      {/* ──────────────────────────────────────────────────────────── */}
      {/* ❤️  LIKE POPUP — warm pink heart burst, auto-dismiss        */}
      {/* ──────────────────────────────────────────────────────────── */}
      <LikePopupModal
        showLikePopup={showLikePopup}
        likePopupProfile={likePopupProfile}
      />

      {/* ──────────────────────────────────────────────────────────── */}
      {/* ✕  PASS POPUP — cool X burst, auto-dismiss                  */}
      {/* ──────────────────────────────────────────────────────────── */}
