    </div>;
};
export default MatchPage;

import i18n from "@/i18n";
import { useTranslation } from "react-i18next";
import React, { useState, useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, Star, Check, Send, ThumbsUp, AlertTriangle } from "lucide-react";
import { toast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/lib/supabaseClient";

// ─── Types ───────────────────────────────────────
interface Review {
  id: string;
  reviewerName: string;
  reviewerPhoto: string;
  rating: number;
  tags: string[];
  text: string;
  date: string;
  verified: boolean;
}
interface MetUser {
  id: string;
  name: string;
  photo: string;
  destination: string;
  meetDate: string;
  reviewed: boolean;
}

// Mock data removed



// ─── StarRating ───────────────────────────────────
const StarRating = ({
  value,
  onChange
}: {
  value: number;
  onChange: (v: number) => void;
}) => <div className="flex gap-1">
    {[1, 2, 3, 4, 5].map(s => <motion.button key={s} whileTap={{
    scale: 0.85
  }} onClick={() => onChange(s)}>
        <Star size={28} className={s <= value ? "text-amber-400 fill-amber-400" : "text-muted-foreground"} />
      </motion.button>)}
  </div>;

// ─── WriteReview modal ────────────────────────────
interface WriteReviewProps {
  user: MetUser;
  onClose: () => void;
  onSubmit: (userId: string) => void;
}
const WriteReview = ({
  user,
  onClose,
  onSubmit
}: WriteReviewProps) => {
  const { t } = useTranslation();

  const POSITIVE_TAGS = useMemo(() => [
    t("auto.g_0781", "시간약속 지킴"),
    t("auto.g_0782", "대화가 즐거웠어요"),
    t("auto.g_0762", "배려심 있어요"),
    t("auto.g_0763", "지식이 풍부해요"),
    t("auto.g_0764", "안전한 노느춴어요"),
    t("auto.g_0783", "또 만나고 싶어요"),
    t("auto.g_0765", "현지 맛집을 잘 알아요"),
    t("auto.g_0766", "사진을 잘 찍어줘요"),
  ], [t]);

  const CAUTION_TAGS = useMemo(() => [
    t("auto.g_0767", "놀쇼 / 지각"),
    t("auto.g_0768", "불편한 대화"),
    t("auto.g_0769", "배려심 부족"),
  ], [t]);

  const [rating, setRating] = useState(0);
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [text, setText] = useState("");
  const [step, setStep] = useState<"rate" | "tags" | "text">("rate");
  const {
    user: me
  } = useAuth();
  const toggleTag = (tag: string) => {
    setSelectedTags(prev => prev.includes(tag) ? prev.filter(t => t !== tag) : [...prev, tag]);
  };
  const handleSubmit = async () => {
    if (rating === 0) {
      toast({
        title: i18n.t("meetReview.noRating"),
        variant: "destructive"
      });
      return;
    }
    if (!me) {
      toast({
        title: i18n.t("alert.t65Title")
      });
      return;
    }
    await supabase.from('meet_reviews').insert({
      reviewer_id: me.id,
      target_id: user.id,
      rating,
      tags: selectedTags,
      text,
      meet_date: user.meetDate,
      destination: user.destination
    });
    onSubmit(user.id);
    toast({
      title: i18n.t("auto.t_0021", "Review submitted!")
    });
    onClose();
  };
  return <motion.div className="fixed inset-0 z-[70] flex items-end justify-center px-safe pb-safe pt-safe" initial={{
    opacity: 0
  }} animate={{
    opacity: 1
  }} exit={{
    opacity: 0
  }}>
      <div className="absolute inset-0 bg-foreground/60 backdrop-blur-md" onClick={onClose} />
      <motion.div className="relative z-10 w-full max-w-lg mx-auto bg-card rounded-3xl mb-4 sm:mb-8 p-6 pb-12 shadow-float" initial={{
      y: "100%"
    }} animate={{
      y: 0
    }} exit={{
      y: "100%"
    }} transition={{
      type: "spring",
      damping: 28,
      stiffness: 300
    }}>
        <div className="w-10 h-1 bg-border rounded-full mx-auto mb-5" />

        {/* User preview */}
        <div className="flex items-center gap-3 mb-5">
          <img src={user.photo} alt={user.name} className="w-12 h-12 rounded-2xl object-cover" />
          <div>
            <p className="font-extrabold text-foreground truncate">{i18n.t("auto.g_0770", "Review: ")} {user.name}</p>
            <p className="text-xs text-muted-foreground">{user.destination} · {user.meetDate}</p>
          </div>
        </div>

        {/* Step: Rate */}
        <AnimatePresence mode="wait">
          {step === "rate" && <motion.div key="rate" initial={{
          opacity: 0,
          x: 20
        }} animate={{
          opacity: 1,
          x: 0
        }} exit={{
          opacity: 0,
          x: -20
        }}>
              <p className="text-sm font-bold text-foreground mb-3 truncate">{i18n.t("meetReview.overallRate")}</p>
              <div className="flex justify-center mb-3">
                <StarRating value={rating} onChange={setRating} />
              </div>
              <p className="text-center text-sm text-muted-foreground mb-5 truncate">
                {rating === 0 ? i18n.t("meetReview.noRating") : rating === 5 ? i18n.t('meetReview.rate5') : rating === 4 ? i18n.t('meetReview.rate4') : rating === 3 ? i18n.t('meetReview.rate3') : rating === 2 ? i18n.t('meetReview.rate2') : i18n.t('meetReview.rate1')}
              </p>
              <motion.button whileTap={{
            scale: 0.97
          }} onClick={() => rating > 0 && setStep("tags")} className={`w-full py-3.5 rounded-2xl font-extrabold text-sm transition-all ${rating > 0 ? "gradient-primary text-primary-foreground shadow-float" : "bg-muted text-muted-foreground"}`}>
                {i18n.t("auto.j528", "Next")}
              </motion.button>
            </motion.div>}

          {step === "tags" && <motion.div key="tags" initial={{
          opacity: 0,
          x: 20
        }} animate={{
          opacity: 1,
          x: 0
        }} exit={{
          opacity: 0,
          x: -20
        }}>
              <p className="text-sm font-bold text-foreground mb-3 truncate">{i18n.t("meetReview.whatGood")} <span className="text-muted-foreground font-normal truncate">({i18n.t("general.multiSelect")})</span></p>
              <div className="flex flex-wrap gap-2 mb-3">
                {POSITIVE_TAGS.map(tag => <button key={tag} onClick={() => toggleTag(tag)} className={`px-3 py-1.5 rounded-xl text-xs font-medium transition-all ${selectedTags.includes(tag) ? "gradient-primary text-primary-foreground" : "bg-muted text-muted-foreground"}`}>
                    {tag}
                  </button>)}
              </div>
              {rating <= 2 && <>
                  <p className="text-xs font-bold text-destructive mb-2 flex items-center gap-1 truncate"><AlertTriangle size={11} /> {i18n.t("meetReview.anyDiscomfort")}</p>
                  <div className="flex flex-wrap gap-2 mb-3">
                    {CAUTION_TAGS.map(tag => <button key={tag} onClick={() => toggleTag(tag)} className={`px-3 py-1.5 rounded-xl text-xs font-medium transition-all ${selectedTags.includes(tag) ? "bg-destructive text-destructive-foreground" : "bg-muted text-muted-foreground"}`}>
                        {tag}
                      </button>)}
                  </div>
                </>}
              <div className="flex gap-2">
                <button onClick={() => setStep("rate")} className="flex-1 py-3 rounded-2xl border border-border text-foreground text-sm font-semibold">← {i18n.t("general.prev")}</button>
                <motion.button whileTap={{
              scale: 0.97
            }} onClick={() => setStep("text")} className="flex-1 py-3 rounded-2xl gradient-primary text-primary-foreground font-extrabold text-sm">{i18n.t("general.next")} →</motion.button>
              </div>
            </motion.div>}

          {step === "text" && <motion.div key="text" initial={{
          opacity: 0,
          x: 20
        }} animate={{
          opacity: 1,
          x: 0
        }} exit={{
          opacity: 0,
          x: -20
        }}>
              <p className="text-sm font-bold text-foreground mb-3 truncate">{i18n.t("meetReview.detailReview")} <span className="text-muted-foreground font-normal truncate">({i18n.t("general.optional")})</span></p>
              <textarea value={text} onChange={e => setText(e.target.value)} maxLength={200} rows={4} placeholder={i18n.t("meetReview.placeholder")} className="w-full px-4 py-3 rounded-2xl bg-muted text-foreground text-sm placeholder:text-muted-foreground outline-none resize-none border-2 border-transparent focus:border-primary transition-colors mb-1" />
              <p className="text-[10px] text-muted-foreground text-right mb-4">{text.length}/200</p>
              <div className="flex gap-2">
                <button onClick={() => setStep("tags")} className="flex-1 py-3 rounded-2xl border border-border text-foreground text-sm font-semibold">← {i18n.t("general.prev")}</button>
                <motion.button whileTap={{
              scale: 0.97
            }} onClick={handleSubmit} className="flex-1 py-3 rounded-2xl gradient-primary text-primary-foreground font-extrabold text-sm flex items-center justify-center gap-2">
                  <Send size={14} /> {i18n.t("meetReview.submitBtn")}
                </motion.button>
              </div>
            </motion.div>}
        </AnimatePresence>
      </motion.div>
    </motion.div>;
};

// ─── Main Page ────────────────────────────────────
const MeetReviewPage = () => {
  const {
    t
  } = useTranslation();
  const getArr = (k: string, fb: string[]) => {
    const v = t(k, {
      returnObjects: true
    });
    return Array.isArray(v) && v.length ? v : fb;
  };
  const CAUTION_TAGS = getArr("meetReview.cautionTags", [t("auto.g_0771", "Went silent"), t("auto.g_0772", "Broke promise"), t("auto.g_0773", "Disrespectful"), t("auto.g_0774", "Asked for money"), t("auto.g_0775", "Excessive drinking"), t("auto.g_0776", "Unwanted intentions"), t("auto.g_0777", "Mismatched profile")]);
  const navigate = useNavigate();
  const {
    user
  } = useAuth();
  const [tab, setTab] = useState<"write" | "received">("write");
  const [users, setUsers] = useState<MetUser[]>([]);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [writing, setWriting] = useState<MetUser | null>(null);
  useEffect(() => {
    if (!user) return;
    const fetchReviewsAndUsers = async () => {
      // 내가 받은 후기
      const {
        data: revData
      } = await supabase.from('meet_reviews').select('*, profiles!reviewer_id (name, photo_url)').eq('target_id', user.id);
      if (revData) {
        setReviews(revData.map(r => ({
          id: r.id,
          reviewerName: r.profiles?.name || t("auto.g_0778", "Anonymous"),
          reviewerPhoto: r.profiles?.photo_url || "",
          rating: r.rating,
          tags: r.tags || [],
          text: r.text || "",
          date: new Intl.DateTimeFormat(i18n.language || 'en').format(new Date(r.created_at)),
          verified: true
        })));
      }

      // 실제 매칭된 상대 (matches 테이블에서 양방향 매치 조회)
      const {
        data: matchData
      } = await supabase.from('matches').select('user1_id, user2_id').or(`user1_id.eq.${user.id},user2_id.eq.${user.id}`).limit(20);
      if (matchData && matchData.length > 0) {
        const partnerIds = matchData.map((m: any) => m.user1_id === user.id ? m.user2_id : m.user1_id);
        const {
          data: partnerProfiles
        } = await supabase.from('profiles').select('id, name, photo_url, location, created_at').in('id', partnerIds);
        if (partnerProfiles) {
          setUsers(partnerProfiles.map((p: any) => ({
            id: p.id,
            name: p.name || t("auto.g_0779", "Unknown"),
            photo: p.photo_url || "",
            destination: p.location || t("auto.g_0780", "Destination"),
            meetDate: new Intl.DateTimeFormat(i18n.language || 'en').format(new Date(p.created_at)),
            reviewed: false
          })));
        }
      } else {
        // 매칭 기록 없음 → 빈 배열
        setUsers([]);
      }
    };
    fetchReviewsAndUsers();
  }, [user]);
  const avgRating = reviews.length > 0 ? reviews.reduce((s, r) => s + r.rating, 0) / reviews.length : 0;
  const markReviewed = (userId: string) => {
    setUsers(prev => prev.map(u => u.id === userId ? {
      ...u,
      reviewed: true
    } : u));
  };
  return <div className="h-full overflow-y-auto bg-background safe-bottom">
      {/* Header */}
      <header className="flex items-center gap-3 px-5 pt-safe pb-4">
        <button onClick={() => navigate(-1)} className="w-10 h-10 rounded-xl bg-muted flex items-center justify-center active:scale-90">
          <ArrowLeft size={18} className="text-foreground" />
        </button>
        <div className="flex-1">
          <h1 className="text-xl font-extrabold text-foreground truncate">{t("meetReview.title")}</h1>
          <p className="text-xs text-muted-foreground mt-0.5 truncate">{t("meetReview.subtitle")}</p>
        </div>
      </header>

      {/* Stats banner */}
      <div className="mx-5 mb-4 bg-gradient-to-r from-amber-500/10 to-orange-500/10 rounded-2xl p-4 border border-amber-500/20">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-xs text-muted-foreground truncate">{t("review.avgScore")}</p>
            <div className="flex items-center gap-1.5 mt-0.5">
              <Star size={18} className="text-amber-400 fill-amber-400" />
              <span className="text-xl font-extrabold text-foreground">{avgRating.toFixed(1)}</span>
              <span className="text-xs text-muted-foreground">/ 5.0</span>
            </div>
          </div>
          <div className="text-right">
            <p className="text-xs text-muted-foreground truncate">{t("review.receivedReviews")}</p>
            <p className="text-xl font-extrabold text-foreground mt-0.5 truncate">{t("review.count", {
              count: reviews.length
            })}</p>
          </div>
          <div className="text-right">
            <p className="text-xs text-muted-foreground truncate">{t("review.pendingReviews")}</p>
            <p className="text-xl font-extrabold text-primary mt-0.5 truncate">{t("review.count", {
              count: users.filter(u => !u.reviewed).length
            })}</p>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex mx-5 mb-4 bg-muted rounded-2xl p-1 truncate">
        {(["write", "received"] as const).map(tabItem => <button key={tabItem} onClick={() => setTab(tabItem)} className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${tab === tabItem ? "bg-card text-foreground shadow-card" : "text-muted-foreground"}`}>
            {tabItem === "write" ? t("review.tabWrite") : t("review.tabReceived")}
          </button>)}
      </div>

      <div className="px-5 space-y-3">
        {/* Write tab */}
        {tab === "write" && users.length === 0 && <div className="text-center py-12">
            <p className="text-muted-foreground text-sm truncate">{t("review.noMatches")}</p>
            <p className="text-xs text-muted-foreground/60 mt-1 truncate">{t("review.noMatchesDesc")}</p>
          </div>}
        {tab === "write" && users.map(user => <motion.div key={user.id} layout className="bg-card rounded-2xl p-4 flex items-center gap-3 shadow-card">
            {user.photo ? <img src={user.photo} alt={user.name} className="w-14 h-14 rounded-2xl object-cover shrink-0" /> : <div className="w-14 h-14 rounded-2xl shrink-0 gradient-primary flex items-center justify-center">
                <span className="text-white font-extrabold text-xl">{user.name?.[0] ?? "?"}</span>
              </div>}
            <div className="flex-1 truncate">
              <p className="font-bold text-sm text-foreground">{user.name}</p>
              <p className="text-xs text-muted-foreground">{user.destination} · {user.meetDate}</p>
              {user.reviewed && <div className="flex items-center gap-1 mt-1">
                  <Check size={11} className="text-emerald-500" />
                  <span className="text-[10px] text-emerald-500 font-bold truncate">{t("review.doneBadge")}</span>
                </div>}
            </div>
            {!user.reviewed ? <motion.button whileTap={{
          scale: 0.9
        }} onClick={() => setWriting(user)} className="px-3 py-2 rounded-xl gradient-primary text-primary-foreground text-xs font-extrabold shadow-card">
                {t("meetReview.writeReviewBtn")}
              </motion.button> : <ThumbsUp size={18} className="text-emerald-500 shrink-0" />}
          </motion.div>)}

        {/* Received tab */}
        {tab === "received" && reviews.map(review => <motion.div key={review.id} layout className="bg-card rounded-2xl p-4 shadow-card">
            <div className="flex items-center gap-3 mb-3">
              <img src={review.reviewerPhoto} alt={review.reviewerName} className="w-10 h-10 rounded-xl object-cover" />
              <div className="flex-1">
                <div className="flex items-center gap-1.5">
                  <p className="text-sm font-bold text-foreground">{review.reviewerName}</p>
                  {review.verified && <div className="w-4 h-4 rounded-full bg-emerald-500 flex items-center justify-center">
                      <Check size={8} className="text-white" strokeWidth={3} />
                    </div>}
                </div>
