                  </span>
                </div>
                <div className={`grid grid-cols-3 gap-2 truncate p-2 rounded-2xl transition-all ${profilePhotos.length < MIN_PROFILE_PHOTOS ? 'ring-2 ring-rose-500/40 bg-rose-500/5' : 'ring-2 ring-green-500/30 bg-transparent'}`}>
