// ─── Types ───────────────────────────────────────────────
interface TripPlan {
  id: string;
  destination: string;
  startDate: string; // "2026-MM-DD"
  endDate: string;
  emoji: string;
  color: string;
}
interface NearbyUser {
  id: string;
