  const [frontFile, setFrontFile] = useState<File | null>(null);
  const [backFile, setBackFile] = useState<File | null>(null);
  const [frontPreview, setFrontPreview] = useState<string | null>(null);
  const [backPreview, setBackPreview] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);

  // 🚨 [React Bug Fix] 타이머 반환 누수 방어용 Ref
  const timerRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);
  React.useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  const pickFile = (side: "front" | "back") => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = "image/*";
    input.onchange = e => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (!file) return;
      const url = URL.createObjectURL(file);
      if (side === "front") {
        // 이전 preview URL revoke (메모리 누수 방지)
        setFrontPreview(prev => { if (prev) URL.revokeObjectURL(prev); return url; });
        setFrontFile(file);
      } else {
        setBackPreview(prev => { if (prev) URL.revokeObjectURL(prev); return url; });
        setBackFile(file);
      }
    };
    input.click();
  };
  const handleSubmit = async () => {
    if (!frontFile) {
      toast({
        title: i18n.t('verif.id.needFront'),
        variant: "destructive"
      });
      return;
    }
    setUploading(true);
    try {
      // 앞면 업로드 (해상도 중요하므로 3MB, 원본품질 유지)
      const compressedFront = await compressImage(frontFile, { maxSizeMB: 3, maxWidthOrHeight: 2560 });
      const frontExt = compressedFront.name.split(".").pop();
      const frontPath = `id-docs/${userId}_front_${Date.now()}.${frontExt}`;
      const {
        error: frontErr
      } = await supabase.storage.from("avatars").upload(frontPath, compressedFront, {
        upsert: true,
        contentType: compressedFront.type
      });
      if (frontErr) throw frontErr;
      const {
        data: frontUrlData
      } = supabase.storage.from("avatars").getPublicUrl(frontPath);

      // 뒷면 업로드(선택)
      let backUrl: string | null = null;
      if (backFile) {
        const compressedBack = await compressImage(backFile, { maxSizeMB: 3, maxWidthOrHeight: 2560 });
        const backExt = compressedBack.name.split(".").pop();
        const backPath = `id-docs/${userId}_back_${Date.now()}.${backExt}`;
        const {
          error: backErr
        } = await supabase.storage.from("avatars").upload(backPath, compressedBack, {
          upsert: true,
          contentType: compressedBack.type
        });
        if (!backErr) {
          const {
            data: backUrlData
          } = supabase.storage.from("avatars").getPublicUrl(backPath);
          backUrl = backUrlData.publicUrl;
        }
      }

      // id_verifications 테이블 INSERT
      const {
        error: insertErr
      } = await supabase.from("id_verifications").insert({
        user_id: userId,
        id_type: idType,
        front_url: frontUrlData.publicUrl,
        back_url: backUrl,
        status: "pending"
      });
      if (insertErr) throw insertErr;
      setStep("pending");
      // 🚨 [React Bug Fix] 단순 return () => clearTimeout는 onClick에서 동작하지 않는 오개념이므로 useRef로 교체
      timerRef.current = setTimeout(() => { onDone(); }, 2000);
    } catch (e: any) {
      toast({
        title: i18n.t('verif.id.uploadFail'),
        description: e.message,
        variant: "destructive"
      });
    } finally {
      setUploading(false);
    }
  };
  return <motion.div className="fixed inset-0 z-[80] flex items-end justify-center px-safe pb-safe pt-safe" initial={{
    opacity: 0
  }} animate={{
    opacity: 1
  }} exit={{
    opacity: 0
  }}>
      <div className="absolute inset-0 bg-foreground/60 backdrop-blur-md" onClick={onClose} />
      <motion.div className="relative z-10 w-full bg-card rounded-3xl mb-4 sm:mb-8 p-6 max-h-[85vh] overflow-y-auto" initial={{
      y: "100%"
    }} animate={{
      y: 0
    }} exit={{
      y: "100%"
    }} transition={{
      type: "spring",
      damping: 25
    }}>
        <div className="w-10 h-1 rounded-full bg-muted mx-auto mb-5" />

        {step === "guide" && <>
          <div className="w-14 h-14 rounded-2xl bg-violet-500/10 flex items-center justify-center mb-4 mx-auto">
            <CreditCard size={26} className="text-violet-400" />
          </div>
          <h3 className="text-lg font-extrabold text-foreground text-center mb-1 truncate">{i18n.t('verif.id.title')}</h3>
          <p className="text-sm text-muted-foreground text-center mb-5 truncate">{i18n.t('verif.id.desc')}</p>

          <div className="space-y-2 mb-5">
            {idTypes.map(typeItem => <button key={typeItem} onClick={() => setIdType(typeItem)} className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${idType === typeItem ? "border-primary bg-primary/5" : "border-border bg-muted/30"}`}>
                <span className="text-sm font-bold text-foreground">{typeItem}</span>
                {idType === typeItem && <Check size={16} className="text-primary" />}
              </button>)}
          </div>

          <div className="bg-amber-500/5 border border-amber-500/20 rounded-2xl p-3 mb-5">
            <ul className="space-y-1.5">
              {idTips.map(tip => <li key={tip} className="flex items-center gap-2 text-[10px] text-muted-foreground">
                  <Check size={10} className="text-amber-500 shrink-0" /> {tip}
                </li>)}
            </ul>
          </div>

          <motion.button whileTap={{
          scale: 0.97
        }} onClick={() => idType ? setStep("upload") : toast({
          title: i18n.t('verif.id.selectType'),
          variant: "destructive"
        })} className="w-full py-4 rounded-2xl gradient-primary text-primary-foreground font-extrabold">
            {i18n.t("verif.next")}
          </motion.button>
        </>}

        {step === "upload" && <>
          <h3 className="text-lg font-extrabold text-foreground text-center mb-1 truncate">{i18n.t('verif.id.upload', {
            type: idType
          })}</h3>
          <p className="text-sm text-muted-foreground text-center mb-5 truncate">{i18n.t('verif.id.uploadDesc')}</p>

          {/* Front */}
          <div className="mb-4">
            <p className="text-xs font-bold text-muted-foreground mb-2 truncate">{i18n.t('verif.id.front')} <span className="text-destructive truncate">{i18n.t('verif.id.frontRequired')}</span></p>
            <button onClick={() => pickFile("front")} className={`w-full aspect-video rounded-2xl border-2 border-dashed flex items-center justify-center overflow-hidden transition-all ${frontPreview ? "border-primary/40" : "border-border bg-muted"}`}>
              {frontPreview ? <img src={frontPreview} alt="front" className="w-full h-full object-cover" /> : <div className="text-center"><CreditCard size={32} className="text-muted-foreground mx-auto mb-2" /><p className="text-xs text-muted-foreground truncate">{i18n.t('verif.id.tapFront')}</p></div>}
            </button>
          </div>

          {/* Back */}
          <div className="mb-5">
            <p className="text-xs font-bold text-muted-foreground mb-2 truncate">{i18n.t('verif.id.back')} <span className="text-muted-foreground/60 truncate">{i18n.t('verif.id.backOptional')}</span></p>
            <button onClick={() => pickFile("back")} className={`w-full h-28 rounded-2xl border-2 border-dashed flex items-center justify-center overflow-hidden transition-all ${backPreview ? "border-primary/40" : "border-border bg-muted"}`}>
              {backPreview ? <img src={backPreview} alt="back" className="w-full h-full object-cover" /> : <p className="text-xs text-muted-foreground truncate">{i18n.t('verif.id.tapBack')}</p>}
            </button>
          </div>

          <div className="flex gap-3">
            <button onClick={() => setStep("guide")} className="flex-1 py-3 rounded-2xl border border-border text-foreground font-semibold text-sm">{i18n.t('verif.id.prev')}</button>
