                <div className="flex justify-between">
                  <span className="text-muted-foreground truncate">{t("auto.g_1303", "상태")}</span>
                  <span className={`font-bold ${selected.status === "resolved" ? "text-emerald-400" : selected.is_sos ? "text-red-400" : "text-blue-400"}`}>
                    {selected.status === "resolved"
                      ? t("auto.g_1304", "처리완료")
                      : selected.is_sos ? "🆘 SOS"
                      : t("auto.g_1305", "활성")}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground truncate">{t("auto.g_1306", "국가위치")}</span>
                  <span className="font-bold text-foreground truncate">{selected.location_name || t("auto.g_1307", "위치없음")}</span>
                </div>
                {selected.latitude && <div className="flex justify-between">
                  <span className="text-muted-foreground truncate">{t("auto.g_1308", "좌표")}</span>
                  <span className="font-mono text-xs">{selected.latitude?.toFixed(4)}, {selected.longitude?.toFixed(4)}</span>
                </div>}
                <div className="flex justify-between">
                  <span className="text-muted-foreground truncate">{t("auto.g_1309", "체크인시각")}</span>
                  <span>{new Date(selected.created_at || selected.checked_at).toLocaleString()}</span>
                </div>
                {selected.status !== "resolved" && (
                  <button onClick={() => { handleResolve(selected.id); setSelected(null); }}
                    className="w-full mt-2 py-3 rounded-2xl bg-emerald-500/10 text-emerald-400 font-bold hover:bg-emerald-500/20 transition-colors">
                    {t("auto.g_1310", "처리완료로변경")}
                  </button>
                )}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AdminSafetyCheckins;

import i18n from "@/i18n";
import { useTranslation } from "react-i18next";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Check, Search, Crown, Ban, Trash2, X, FileText, ChevronDown, RefreshCw } from "lucide-react";
import { toast } from "@/hooks/use-toast";
import {
  fetchAdminUsers, updateUserValidation, updateUserPlan,
  updateUserBan, deleteUserAccount, updateUserNote,
  adminBanUser, adminUnbanUser
} from "@/lib/adminService";
type FilterType = "all" | "verified" | "unverified" | "plus" | "premium" | "banned";
export const AdminUsers = () => {
  const {
    t
  } = useTranslation();
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState("");
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState<FilterType>("all");
  const [selectedUser, setSelectedUser] = useState<any | null>(null);
  const [noteEdit, setNoteEdit] = useState("");
  const [savingNote, setSavingNote] = useState(false);
  const [confirmingBan, setConfirmingBan] = useState<string | null>(null);
  const [confirmingDelete, setConfirmingDelete] = useState<string | null>(null);
  const load = async () => {
    setLoading(true);
    setLoadError("");
    try {
      const dbUsers = await fetchAdminUsers();
      setUsers(dbUsers || []);
    } catch (e: any) {
      console.error("AdminUsers load error:", e);
      setLoadError(i18n.t("auto.z_\uC720\uC800\uBAA9\uB85D\uC744\uBD88\uB7EC\uC624\uC9C0\uBABB_883", "\uC720\uC800\uBAA9\uB85D\uC744\uBD88\uB7EC\uC624\uC9C0\uBABB") + e.message + ")");
      setUsers([]);
    } finally {
      setLoading(false);
    }
  };
  useEffect(() => {
    load();
  }, []);
  const filtered = users.filter(u => {
    const q = search.toLowerCase();
    const match = (u.name || "").toLowerCase().includes(q) || (u.email || "").toLowerCase().includes(q) || (u.nationality || "").toLowerCase().includes(q);
    if (!match) return false;
    if (filter === "verified") return u.verified && !u.banned;
    if (filter === "unverified") return !u.verified && !u.banned;
    if (filter === "plus") return u.plan === "plus" || u.is_plus && u.plan !== "premium";
    if (filter === "premium") return u.plan === "premium";
    if (filter === "banned") return u.banned;
    return true;
  });
  const verifyUser = async (id: string, currentVerified: boolean) => {
    const success = await updateUserValidation(id, !currentVerified);
    if (success) {
      setUsers(prev => prev.map(u => u.id === id ? { ...u, verified: !currentVerified } : u));
      if (selectedUser?.id === id) setSelectedUser((p: any) => ({ ...p, verified: !currentVerified }));
      toast({
        title: !currentVerified ? "✅ 인증 승인 완료" : "⚠️ 인증 취소",
        description: !currentVerified ? "사용자에게 푸시 알림이 발송되었습니다." : "인증이 취소되었습니다."
      });
    } else {
      toast({ title: "❌ 실패", description: "인증 상태 변경에 실패했습니다.", variant: "destructive" });
    }
  };
  const cyclePlan = async (id: string, currentPlan: string, is_plus: boolean) => {
    let nextPlan: 'free' | 'plus' | 'premium' = 'free';
    const plan = currentPlan || (is_plus ? 'plus' : 'free');
    if (plan === 'free') nextPlan = 'plus'; else if (plan === 'plus') nextPlan = 'premium'; else nextPlan = 'free';
    const success = await updateUserPlan(id, nextPlan);
    if (success) {
      setUsers(prev => prev.map(u => u.id === id ? {
        ...u,
        plan: nextPlan,
        is_plus: nextPlan !== 'free'
      } : u));
      if (selectedUser?.id === id) setSelectedUser((p: any) => ({
        ...p,
        plan: nextPlan,
        is_plus: nextPlan !== 'free'
      }));
    }
  };
  const toggleBan = async (id: string, currentBanned: boolean) => {
    if (confirmingBan !== id) {
      setConfirmingBan(id);
      setTimeout(() => setConfirmingBan(null), 3000);
      return;
    }
    setConfirmingBan(null);
    // RPC 내장 함수 우선 시도 (ban_reason, banned_until 지원)
    const success = currentBanned
      ? await adminUnbanUser(id)
      : await adminBanUser(id);
    // RPC 실패 시 fallback
    const finalSuccess = success !== false
      ? success
      : await updateUserBan(id, !currentBanned);
    if (finalSuccess) {
      setUsers(prev => prev.map(u => u.id === id ? { ...u, banned: !currentBanned } : u));
      if (selectedUser?.id === id) setSelectedUser((p: any) => ({ ...p, banned: !currentBanned }));
      toast({
        title: !currentBanned ? "🚫 계정 정지 완료" : "✅ 계정 정지 해제 완료",
        description: !currentBanned ? "사용자에게 알림이 발송되었습니다." : "사용자가 다시 서비스를 이용할 수 있습니다."
      });
    } else {
      toast({ title: "❌ 실패", description: "계정 정지/해제에 실패했습니다.", variant: "destructive" });
    }
  };
  const handleDelete = async (id: string) => {
    if (confirmingDelete !== id) {
      setConfirmingDelete(id);
      setTimeout(() => setConfirmingDelete(null), 3000);
      return;
    }
    setConfirmingDelete(null);
    const success = await deleteUserAccount(id);
    if (success) {
      setUsers(prev => prev.filter(u => u.id !== id));
      setSelectedUser(null);
      toast({ title: "✅ 계정 영구 삭제 완료" });
    } else {
      toast({ title: "❌ 실패", description: "계정 삭제에 실패했습니다.", variant: "destructive" });
    }
  };
  const saveNote = async () => {
    if (!selectedUser) return;
    setSavingNote(true);
    const success = await updateUserNote(selectedUser.id, noteEdit);
    if (success) {
      setUsers(prev => prev.map(u => u.id === selectedUser.id ? {
        ...u,
        admin_note: noteEdit
      } : u));
      setSelectedUser((p: any) => ({
        ...p,
        admin_note: noteEdit
      }));
    }
    setSavingNote(false);
  };
  const filterButtons: {
    key: FilterType;
    label: string;
  }[] = [{
    key: "all",
    label: t("auto.t5005", {
      v0: users.length
    })
  }, {
    key: "unverified",
    label: t("auto.p7", {
      count: users.filter(u => !u.verified && !u.banned).length
    })
  }, {
    key: "verified",
    label: t("auto.p8", {
      count: users.filter(u => u.verified).length
    })
  }, {
    key: "plus",
    label: `Plus (${users.filter(u => u.plan === "plus" || u.is_plus && u.plan !== "premium").length})`
  }, {
    key: "premium",
    label: `Premium (${users.filter(u => u.plan === "premium").length})`
  }, {
    key: "banned",
    label: t("auto.p9", {
      count: users.filter(u => u.banned).length
    })
  }];
  return <div className="truncate">
    <div className="flex items-center justify-between mb-6">
      <div>
        <h1 className="text-2xl font-extrabold text-foreground truncate">{t("admin.userManagement", "유저 관리")}</h1>
        <p className="text-sm text-muted-foreground truncate">{t("admin.totalUsersRealtime", { count: users.length, defaultValue: "전체 {{count}}명 등록 (실시간)" })}</p>
      </div>
      <motion.button whileTap={{
        scale: 0.95
      }} onClick={load} className="flex items-center gap-2 px-3 py-2 rounded-xl bg-muted text-muted-foreground hover:text-foreground text-sm transition-colors">
        <RefreshCw size={14} className={loading ? "animate-spin" : ""} />{t("admin.refresh", "새로고침")}
      </motion.button>
    </div>

    {/* 에러 배너 */}
    {loadError && <div className="mb-4 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/30 flex items-center justify-between gap-3">
      <p className="text-sm text-red-500 font-semibold">{loadError}</p>
      <button onClick={load} className="shrink-0 text-xs font-bold text-red-500 underline">{t("auto.z_\uC7AC\uC2DC\uB3C4_892", "\uC7AC\uC2DC\uB3C4")}</button>
    </div>}

    {/* 검색 + 필터 */}
    <div className="flex gap-3 mb-5">
      <div className="relative flex-1">
        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder={t("auto.g_1318", "이름이메일")} className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-muted border border-border text-sm text-foreground placeholder:text-muted-foreground outline-none focus:border-primary transition-colors" />
      </div>
      <div className="flex gap-1.5 flex-wrap">
        {filterButtons.map(b => <button key={b.key} onClick={() => setFilter(b.key)} className={`px-3 py-2 rounded-xl text-xs font-semibold whitespace-nowrap transition-all ${filter === b.key ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:bg-muted/80"}`}>
          {b.label}
        </button>)}
      </div>
    </div>

    {/* 테이블 (3열) */}
    <div className="bg-card rounded-2xl border border-border overflow-hidden truncate">
      {loading ? <div className="py-16 flex items-center justify-center gap-3 text-muted-foreground">
        <div className="w-5 h-5 border-2 border-primary border-t-transparent rounded-full animate-spin" />
        <span className="text-sm truncate">{t("auto.g_1319", "불러오는중")}</span>
      </div> : <table className="w-full">
        <thead>
