                  <Crown size={12} />
                </motion.button>
                <motion.button whileTap={{ scale: 0.9 }} onClick={() => toggleBan(u.id, u.banned)} className={`p-1.5 rounded-lg transition-colors ${u.banned ? "bg-emerald-500/10 text-emerald-400" : "bg-red-500/10 text-red-400 hover:bg-red-500/20"}`} title={u.banned ? t("auto.g_1326", "정지해제6") : t("auto.g_1327", "계정정지6")}>
