import i18n from "@/i18n";
import React, { useState, useCallback, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, MoreVertical, ShieldAlert, Phone, CheckSquare, Shield, Crown, AlertTriangle, Languages, ChevronDown, Check, MapPin, Calendar, Map, Lock, Send, Globe } from "lucide-react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { LANG_NAMES, SupportedLang } from "@/lib/translateService";
import { MeetProposalModal, ScheduleShareModal, ReportModal, DeleteConfirmModal } from "./ChatModals";
import MigoPlusModal from "@/components/MigoPlusModal";
import SOSModal from "@/components/SOSModal";
import ProfileDetailSheet from "@/components/ProfileDetailSheet";
import ReportBlockActionSheet from "@/components/ReportBlockActionSheet";
import { triggerHaptic } from "@/lib/haptics";
import { useRealtimeChat } from "@/hooks/useRealtimeChat";
import { useAuth } from "@/hooks/useAuth";

export interface ChatRoomProps {
  // State from parent
  thread: any;
  selectedChat: string | null;
  setSelectedChat: (id: string | null) => void;
  isMuted: boolean;
  isLocked: boolean;
  messages: any[];
  bottomRef: React.RefObject<HTMLDivElement>;

  // Subscription
  isPlus: boolean;
  canReadReceipts: boolean;
  setShowPlusModal: (v: boolean) => void;
  showPlusModal: boolean;

  // Actions
  handleToggleMute: (chatId: string, name: string) => void;
  handleNoShowReport: () => void;
  handleShareLocation: () => void;
  sendMessage: () => void;
  handleDeleteChat: (chatId: string) => void;
  handleReport: () => void;
  handleMeetProposal: () => void;
  handleScheduleShare: () => void;

  // Translation
  autoTranslate: boolean;
  setAutoTranslate: React.Dispatch<React.SetStateAction<boolean>>;
  targetLang: SupportedLang;
  setTargetLang: React.Dispatch<React.SetStateAction<SupportedLang>>;
  translateMap: Record<string, string>;
  loadingMap: Record<string, boolean>;
  handleTranslate: (msgId: string, text: string) => void;

  // Form State
  message: string;
  setMessage: (v: string) => void;

  // Modals / Overlays
  showMoreMenu: boolean;
  setShowMoreMenu: React.Dispatch<React.SetStateAction<boolean>>;
  showLangPicker: boolean;
  setShowLangPicker: React.Dispatch<React.SetStateAction<boolean>>;
  showMeetProposal: boolean;
  setShowMeetProposal: React.Dispatch<React.SetStateAction<boolean>>;
  showScheduleModal: boolean;
  setShowScheduleModal: React.Dispatch<React.SetStateAction<boolean>>;
  showReportModal: boolean;
  setShowReportModal: React.Dispatch<React.SetStateAction<boolean>>;
  reportReason: string;
  setReportReason: (v: string) => void;
  showDeleteConfirm: boolean;
  setShowDeleteConfirm: React.Dispatch<React.SetStateAction<boolean>>;
  showSOS: boolean;
  setShowSOS: React.Dispatch<React.SetStateAction<boolean>>;
  viewingProfile: any | null;
  setViewingProfile: React.Dispatch<React.SetStateAction<any | null>>;
  actionSheetTarget: any | null;
  setActionSheetTarget: React.Dispatch<React.SetStateAction<any | null>>;

  // Meet / Schedule State
  meetDate: string;
  setMeetDate: (v: string) => void;
  meetPlace: string;
  setMeetPlace: (v: string) => void;
  scheduleDate: string;
  setScheduleDate: (v: string) => void;
  scheduleText: string;
  setScheduleText: (v: string) => void;
}

export const ChatRoom: React.FC<ChatRoomProps> = ({
  thread, selectedChat, setSelectedChat, isMuted, isLocked, messages: _messagesProp, bottomRef,
  isPlus, canReadReceipts, setShowPlusModal, showPlusModal,
  handleToggleMute, handleNoShowReport, handleShareLocation, sendMessage, handleDeleteChat, handleReport, handleMeetProposal, handleScheduleShare,
  autoTranslate, setAutoTranslate, targetLang, setTargetLang, translateMap, loadingMap, handleTranslate,
  message, setMessage,
  showMoreMenu, setShowMoreMenu,
  showLangPicker, setShowLangPicker,
  showMeetProposal, setShowMeetProposal,
  showScheduleModal, setShowScheduleModal,
  showReportModal, setShowReportModal, reportReason, setReportReason,
  showDeleteConfirm, setShowDeleteConfirm,
  showSOS, setShowSOS,
  viewingProfile, setViewingProfile,
  actionSheetTarget, setActionSheetTarget,
  meetDate, setMeetDate, meetPlace, setMeetPlace,
  scheduleDate, setScheduleDate, scheduleText, setScheduleText
}) => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { user } = useAuth();

  // ── 내부 메시지 상태 (useRealtimeChat으로 직접 관리) ──
  const [localMessages, setLocalMessages] = useState<any[]>([]);
  const localBottomRef = useRef<HTMLDivElement>(null);

  const { fetchMessages } = useRealtimeChat({
    threadId: selectedChat,
    onMessage: (newMsg) => {
      const formatted = {
        id: newMsg.id,
        sender: newMsg.sender_id === user?.id ? 'me' : 'other',
        text: newMsg.text,
        time: new Date(newMsg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      };
      setLocalMessages(prev => {
        // 낙관적 UI 중복 방지: 같은 id 이미 있으면 교체, 없으면 append
        const exists = prev.findIndex(m => m.id === newMsg.id);
        if (exists !== -1) {
          const next = [...prev];
          next[exists] = formatted;
          return next;
        }
        return [...prev, formatted];
      });
    },
  });

  // 채팅방 진입 시 기존 메시지 초기 로딩
  useEffect(() => {
    if (!selectedChat) return;
    setLocalMessages([]);
    fetchMessages().then((msgs) => {
      const formatted = msgs.map(m => ({
        id: m.id,
        sender: m.sender_id === user?.id ? 'me' : 'other',
        text: m.text,
        time: new Date(m.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      }));
      setLocalMessages(formatted);
    });
  }, [selectedChat]); // eslint-disable-line react-hooks/exhaustive-deps

  // 메시지 추가될 때마다 스크롤 아래로
  useEffect(() => {
    localBottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [localMessages]);

  // 실제 렌더링에 사용할 메시지 배열
  const messages = localMessages;

  // ── 번역해서 보내기 상태 (Free: 하루 3회, Plus 무제한) ──
  const [translateSending, setTranslateSending] = useState(false);
  const FREE_DAILY_TRANSLATE_SEND = 3;
  const todayKey = `migo_translate_send_${new Date().toISOString().slice(0, 10)}`;
  const getTranslateSendCount = () => parseInt(localStorage.getItem(todayKey) || '0', 10);
  const incrementTranslateSendCount = () => localStorage.setItem(todayKey, String(getTranslateSendCount() + 1));

  const handleTranslateSend = useCallback(async () => {
    if (!message.trim()) return;
    if (!isPlus) {
      const used = getTranslateSendCount();
      if (used >= FREE_DAILY_TRANSLATE_SEND) {
        setShowPlusModal(true);
        return;
      }
    }
    setTranslateSending(true);
    try {
      const { translateText } = await import('@/lib/translateService');
      const translated = await translateText({ text: message, targetLang });
      const textToSend = (translated && translated !== message) ? translated : message;
      // setState 후 sendMessage가 최신 값을 읽도록 setTimeout(0)으로 React batch flush 보장
      setMessage(textToSend);
      setTimeout(() => {
        sendMessage();
      }, 0);
      if (!isPlus && translated && translated !== message) incrementTranslateSendCount();
    } catch {
      sendMessage();
    } finally {
      setTranslateSending(false);
    }
  }, [message, targetLang, isPlus, sendMessage, setMessage]);


  return (
    <div className="flex flex-col h-screen bg-background overflow-hidden">
      {/* Header (Backdrop Blur) */}
      <header className="sticky top-0 z-20 pt-safe bg-background/80 backdrop-blur-xl border-b border-border/50">
        <div className="flex items-center gap-3 px-4 py-3">
          <button onClick={() => setSelectedChat(null)} className="transition-transform active:scale-90 p-1 -ml-1">
            <ArrowLeft size={22} className="text-foreground" />
          </button>
          {thread?.photo ? (
            <img src={thread.photo} alt="" className="w-10 h-10 rounded-full object-cover shadow-sm border border-border/10" loading="lazy" onError={e => { (e.target as HTMLImageElement).style.display = 'none'; }} />
          ) : (
            <div className="w-10 h-10 rounded-full gradient-primary flex items-center justify-center text-primary-foreground text-sm font-bold shadow-sm">
              {thread?.name?.[0] ?? "?"}
            </div>
          )}
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-1.5 min-w-0">
              <h3 className="font-extrabold text-[15px] text-foreground truncate pl-0.5">{thread?.name}</h3>
              {isMuted && <span className="text-[9px] bg-muted px-1.5 py-0.5 rounded-full text-muted-foreground font-bold shrink-0">🔕</span>}
            </div>
            <span className={`text-[11px] font-bold pl-0.5 ${thread?.online ? "text-emerald-500" : "text-muted-foreground"}`}>{thread?.online ? i18n.t('chat.online') : i18n.t('chat.offline')}</span>
          </div>
          <div className="flex items-center gap-1.5">
            {/* 신고/차단 버튼 — Guideline 1.2 직접 노출 */}
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => { triggerHaptic("warning"); setActionSheetTarget(thread); }} className="w-9 h-9 flex items-center justify-center rounded-full text-red-400 bg-red-500/10 transition-colors hover:bg-red-500/20 border border-red-500/20">
              <ShieldAlert size={16} />
            </motion.button>
            <motion.button whileTap={{ scale: 0.9 }} onClick={() => navigate("/voice-call", { state: { contactId: thread?.id ?? "u1" } })} className="w-9 h-9 flex items-center justify-center rounded-full text-white bg-indigo-500 transition-colors hover:bg-indigo-600 shadow-md">
              <Phone size={15} fill="currentColor" />
            </motion.button>
            <div className="relative">
              <button onClick={() => setShowMoreMenu(v => !v)} className="w-9 h-9 flex items-center justify-center rounded-full transition-colors hover:bg-muted ml-1">
                <MoreVertical size={20} className="text-foreground" />
              </button>
              <AnimatePresence>
                {showMoreMenu && (
                  <motion.div className="absolute right-0 top-11 bg-card/95 backdrop-blur-md border border-border/60 rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] p-1.5 min-w-[240px] z-[100]" initial={{ opacity: 0, scale: 0.95, y: -4 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: -4 }}>
                    <div className="fixed inset-0 z-[-1]" onClick={() => setShowMoreMenu(false)} />
                    <button onClick={() => { setShowMoreMenu(false); navigate("/trip-review", { state: { partnerName: thread?.name, partnerPhoto: thread?.photo, threadId: selectedChat, destination: i18n.t("auto.x4007") } }); }} className="w-full text-left px-4 py-3 text-[13px] font-bold text-emerald-600 rounded-2xl hover:bg-emerald-500/10 transition-colors flex items-center gap-2.5">
                      <CheckSquare size={14} />{i18n.t("auto.x4006")}
                    </button>
                    <button onClick={async () => { 
                        setShowMoreMenu(false); 
                        if (thread?.opponentId) {
                          // Profile view logic depends on passing appropriate args, or resolving at parent. 
                          // Handled correctly by parent if we pass setViewingProfile
                          setViewingProfile({ id: thread.opponentId }); // Simplified for extraction wrapper
                        }
                      }} className="w-full text-left px-4 py-3 text-[13px] font-semibold text-foreground rounded-2xl hover:bg-muted transition-colors">{i18n.t('chat.viewProfile')}
                    </button>
                    <button onClick={() => handleToggleMute(selectedChat!, thread?.name ?? "")} className="w-full text-left px-4 py-3 text-[13px] font-semibold text-foreground rounded-2xl hover:bg-muted transition-colors">
                      {isMuted ? i18n.t('chat.muteOff') : i18n.t('chat.muteOn')}
                    </button>
                    <button onClick={() => { setShowMoreMenu(false); setActionSheetTarget(thread); }} className="w-full text-left px-4 py-3 text-[13px] font-semibold text-red-500 rounded-2xl hover:bg-red-500/5 transition-colors">{i18n.t('chat.report')}</button>
                    <button onClick={() => { setShowMoreMenu(false); setShowDeleteConfirm(true); }} className="w-full text-left px-4 py-3 text-[13px] font-semibold text-red-500 rounded-2xl hover:bg-red-500/5 transition-colors">{i18n.t('chat.deleteChat')}</button>
                    <button onClick={() => { setShowMoreMenu(false); setShowSOS(true); }} className="w-full text-left px-4 py-3 text-[13px] font-bold text-orange-500 rounded-2xl hover:bg-orange-500/10 transition-colors flex items-center gap-2.5">
                      <AlertTriangle size={14} />{i18n.t('sos.title')}
                    </button>
                    <button onClick={() => { setShowMoreMenu(false); }} className="w-full text-left px-4 py-3 text-[13px] font-bold text-emerald-600 rounded-2xl hover:bg-emerald-500/10 transition-colors flex items-center gap-2.5">
                      <Shield size={14} /> {i18n.t('chat.safeCompanionBtn')}
                    </button>

                    {isPlus && (
                      <div className="pt-1.5 mt-1.5 border-t border-border/50">
                        <button onClick={handleNoShowReport} className="w-full text-left px-4 py-3 text-[13px] font-bold text-rose-500 rounded-2xl hover:bg-rose-500/10 transition-colors flex items-center gap-2.5">
                          <Crown size={14} className="text-rose-500" />
                          {i18n.t('chat.noShowReport')}
                        </button>
                      </div>
                    )}
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
          </div>
        </div>

      </header>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-3">
        {messages.map((msg, idx) => {
          const isMe = msg.sender === "me";
          const isLastMine = isMe && messages.slice(idx + 1).every(m => m.sender !== "me");
          const translated = translateMap[msg.id];
          const isTranslating = loadingMap[msg.id];
          return (
            <div key={msg.id} className={`flex flex-col ${isMe ? "items-end" : "items-start"} gap-1`}>
              <div className={`max-w-[78%] px-4 py-3 text-[14.5px] leading-relaxed whitespace-pre-line shadow-sm border border-black/5 dark:border-white/5 ${isMe ? "bg-primary text-primary-foreground rounded-[22px] rounded-br-[4px]" : "bg-card text-foreground rounded-[22px] rounded-bl-[4px]"}`}>
                {msg.text.startsWith(i18n.t("auto.g_1378", "현재위치공")) ? (
                  <div className="flex gap-3.5 items-center">
                    <div className="w-11 h-11 rounded-full flex items-center justify-center shrink-0 bg-blue-500/15">
                      <MapPin size={22} className="text-blue-500" />
                    </div>
                    <div>
                      <p className="text-[11px] font-black text-blue-500 mb-0.5 tracking-wider uppercase truncate">{i18n.t('chat.myCurrentLocation')}</p>
                      <p className="text-[14px] font-extrabold text-foreground mb-1 line-clamp-1">{msg.text.split('\n')[1] || i18n.t('chat.locationUnknown')}</p>
                      <a href={msg.text.split('\n')[2] || "#"} target="_blank" rel="noopener noreferrer" className="text-[11px] font-bold text-blue-500 hover:text-blue-600 transition-colors underline underline-offset-2">{i18n.t('chat.openMap')}</a>
                    </div>
                  </div>
                ) : msg.text.startsWith(i18n.t("auto.g_1379", "만남제안4")) ? (
                  <div className="flex gap-3.5 items-center">
                    <div className="w-11 h-11 rounded-full flex items-center justify-center shrink-0 bg-orange-500/15">
                      <Calendar size={22} className="text-orange-500" />
                    </div>
                    <div>
                      <p className="text-[11px] font-black text-orange-500 mb-0.5 tracking-wider uppercase truncate">{i18n.t('chat.meetProposal')}</p>
                      <p className="text-[14px] font-extrabold text-foreground mb-1 truncate">{msg.text.split('\n')[1]?.replace(i18n.t("auto.g_1380", "날짜"), '') || ""}</p>
                      <p className="text-[12px] font-semibold text-muted-foreground truncate">{msg.text.split('\n')[2]?.replace(i18n.t("auto.g_1381", "장소"), '') || ""}</p>
                    </div>
                  </div>
                ) : msg.text.startsWith(i18n.t("auto.g_1382", "여행일정공")) ? (
                  <div className="flex gap-3.5 items-start">
                    <div className="w-11 h-11 rounded-full flex items-center justify-center shrink-0 bg-green-500/15 mt-1">
                      <Map size={22} className="text-green-500" />
                    </div>
                    <div className="flex-1">
                      <p className="text-[11px] font-black text-green-500 mb-0.5 tracking-wider uppercase truncate">{i18n.t('chat.ourSchedule')}</p>
                      <p className="text-[12px] font-extrabold text-foreground mb-1.5 bg-foreground/5 inline-block px-2 py-0.5 rounded-lg text-left truncate">{msg.text.split('\n')[1]?.replace(i18n.t("auto.g_1383", "일시"), '')}</p>
                      <p className="text-[14px] font-medium text-foreground text-left truncate">{msg.text.split('\n').slice(2).join('\n').replace(i18n.t("auto.g_1384", "내용"), '')}</p>
                    </div>
                  </div>
                ) : <span className="font-medium tracking-tight break-words">{msg.text}</span>}

                <div className={`flex items-center ${isMe ? "justify-end" : "justify-start"} gap-1.5 mt-2`}>
                  <span className={`text-[10px] font-bold ${isMe ? "text-primary-foreground/70" : "text-muted-foreground"}`}>{msg.time}</span>
                  {isMe && canReadReceipts && (
                    <span className={`text-[10px] font-black flex items-center gap-0.5 ${isLastMine ? "text-primary-foreground/50" : "text-emerald-300"}`}>
                      <Check size={10} strokeWidth={3} />
                      <Check size={10} strokeWidth={3} className="-ml-2" />
                      {!isLastMine && <span className="text-[9px] drop-shadow-sm ml-0.5 tracking-tight truncate">{i18n.t('chat.read')}</span>}
                    </span>
                  )}
                </div>
              </div>

              {/* Translate button */}
              <motion.button whileTap={{ scale: 0.95 }} onClick={() => handleTranslate(msg.id, msg.text)} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-extrabold transition-all mt-1 ${translated ? "bg-indigo-500 text-white shadow-sm" : "bg-card border border-border/50 text-muted-foreground hover:text-foreground"}`}>
                {isTranslating ? <motion.div className="w-3.5 h-3.5 border-2 border-indigo-400 border-t-transparent rounded-full" animate={{ rotate: 360 }} transition={{ duration: 0.7, repeat: Infinity, ease: "linear" }} /> : <Languages size={12} />}
                {isTranslating ? i18n.t('chat.translating') : translated ? i18n.t('chat.viewOriginal') : `${i18n.t('chat.translate')} (${LANG_NAMES[targetLang]})`}
              </motion.button>

              {/* Translated result */}
              <AnimatePresence>
                {translated && (
                  <motion.div initial={{ opacity: 0, y: -4, scale: 0.97 }} animate={{ opacity: 1, y: 0, scale: 1 }} exit={{ opacity: 0, y: -4, scale: 0.97 }} className={`max-w-[78%] px-4 py-3 text-[14.5px] leading-relaxed shadow-sm border ${isMe ? "rounded-[22px] rounded-br-[4px]" : "rounded-[22px] rounded-bl-[4px]"}`} style={{ background: "rgba(99,102,241,0.06)", borderColor: "rgba(99,102,241,0.15)", color: "var(--foreground)" }}>
                    <div className="flex items-center gap-1.5 mb-1.5 opacity-80">
                      <Languages size={12} className="text-indigo-500" />
                      <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest">{LANG_NAMES[targetLang]}</span>
                    </div>
                    <span className="font-medium tracking-tight break-words">{translated}</span>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
          );
        })}
        <div ref={localBottomRef} />
      </div>

      {/* Locked overlay */}
      {isLocked && (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="mx-4 mb-2 p-4 rounded-3xl bg-gradient-to-br from-amber-500/15 to-orange-500/10 border border-amber-500/30 flex items-center gap-4">
          <div className="w-10 h-10 rounded-2xl bg-amber-500/20 flex items-center justify-center shrink-0">
            <Lock size={18} className="text-amber-500" />
          </div>
          <div className="flex-1">
            <p className="text-sm font-extrabold text-foreground truncate">{i18n.t('chat.dailyLimitTitle')}</p>
            <p className="text-[11px] text-muted-foreground mt-0.5 truncate">{i18n.t('chat.dailyLimitDesc')}</p>
          </div>
          <motion.button whileTap={{ scale: 0.95 }} onClick={() => setShowPlusModal(true)} className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-gradient-to-r from-amber-500 to-orange-500 text-white text-xs font-extrabold shadow-lg shrink-0">
            <Crown size={12} /> Plus
          </motion.button>
        </motion.div>
      )}

      {/* Bottom area: quick actions + input — 한 덩어리로 묶어 항상 화면 안에 */}
      <div className="shrink-0 px-3 pt-1 pb-safe bg-background/95 backdrop-blur-xl border-t border-border/40 z-20"
           style={{ paddingBottom: 'max(env(safe-area-inset-bottom, 8px), 8px)' }}>

        {/* Quick action chips — 얇은 한 줄 */}
        <div className="flex gap-1.5 mb-2 overflow-x-auto scrollbar-hide">
          <button onClick={handleShareLocation} className="flex shrink-0 items-center gap-1 px-2.5 py-1 rounded-full bg-muted text-[11px] font-semibold text-muted-foreground active:scale-95">
            <MapPin size={11} />{i18n.t('chat.shareLocation')}
          </button>
          <button onClick={() => setShowMeetProposal(true)} className="flex shrink-0 items-center gap-1 px-2.5 py-1 rounded-full bg-muted text-[11px] font-semibold text-muted-foreground active:scale-95">
            <Calendar size={11} />{i18n.t('chat.meetProposalBtn')}
          </button>
          <button onClick={() => setShowScheduleModal(true)} className="flex shrink-0 items-center gap-1 px-2.5 py-1 rounded-full bg-muted text-[11px] font-semibold text-muted-foreground active:scale-95">
            <Map size={11} />{i18n.t('chat.scheduleShareBtn')}
          </button>
          {/* 번역 토글 chip */}
          <button onClick={() => setAutoTranslate(v => !v)} className={`flex shrink-0 items-center gap-1 px-2.5 py-1 rounded-full text-[11px] font-semibold active:scale-95 ${autoTranslate ? 'bg-indigo-500 text-white' : 'bg-muted text-muted-foreground'}`}>
            <Languages size={11} />{autoTranslate ? 'AUTO ON' : 'AUTO'}
          </button>
          {/* 언어 선택 chip */}
          <div className="relative shrink-0">
            <button onClick={() => setShowLangPicker(v => !v)} className="flex items-center gap-1 px-2.5 py-1 rounded-full bg-muted text-[11px] font-semibold text-muted-foreground active:scale-95">
              {LANG_NAMES[targetLang]}<ChevronDown size={10} />
            </button>
            <AnimatePresence>
              {showLangPicker && (
                <motion.div className="absolute bottom-8 left-0 bg-card/95 backdrop-blur-md border border-border/60 rounded-2xl shadow-xl p-1.5 z-50 min-w-[130px] max-h-48 overflow-y-auto"
                  initial={{ opacity: 0, scale: 0.95, y: 4 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 4 }}>
                  <div className="fixed inset-0 z-[-1]" onClick={() => setShowLangPicker(false)} />
                  {(Object.entries(LANG_NAMES) as [SupportedLang, string][]).map(([code, name]) => (
                    <button key={code} onClick={() => { setTargetLang(code); setShowLangPicker(false); }}
                      className={`w-full text-left px-3 py-2 text-[12px] rounded-xl transition-colors ${targetLang === code ? 'bg-indigo-500/10 text-indigo-500 font-extrabold' : 'text-foreground font-semibold hover:bg-muted'}`}>
                      {name}
                    </button>
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>

        {/* Input row */}
        <div className={`flex items-center gap-2 rounded-[24px] px-3 py-1.5 border border-border bg-card/90 shadow-sm ${isLocked ? 'opacity-70' : ''}`}>
          <input type="text" value={message} onChange={e => setMessage(e.target.value)} onKeyDown={e => { if (e.key === 'Enter' && !e.nativeEvent.isComposing) sendMessage(); }} placeholder={isLocked ? i18n.t('chat.lockedPlaceholder') : isMuted ? i18n.t('chat.inputMuted') : i18n.t('chat.input')} disabled={isLocked} className="flex-1 min-w-0 bg-transparent text-[15px] font-medium text-foreground placeholder:text-muted-foreground outline-none disabled:cursor-not-allowed px-1 py-2" />
            {/* 번역해서 보내기 */}
            {!isLocked && message.trim() && (
              <motion.button
                whileTap={{ scale: 0.9 }}
                onClick={handleTranslateSend}
                disabled={translateSending}
                title={isPlus ? t('chat.translateSend', `Translate & Send (${LANG_NAMES[targetLang]})`) : t('chat.translateSendFree', `Translate & Send (${Math.max(0, FREE_DAILY_TRANSLATE_SEND - getTranslateSendCount())} free left)`)}
                className={`w-9 h-9 rounded-full flex items-center justify-center shrink-0 transition-all ${
                  translateSending
                    ? 'bg-indigo-400/30 text-indigo-400'
                    : isPlus
                      ? 'bg-indigo-500 text-white shadow-md'
                      : getTranslateSendCount() >= FREE_DAILY_TRANSLATE_SEND
                        ? 'bg-muted text-muted-foreground opacity-50'
                        : 'bg-indigo-500/15 border border-indigo-500/40 text-indigo-500'
                }`}
              >
                {translateSending
                  ? <motion.div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full" animate={{ rotate: 360 }} transition={{ duration: 0.7, repeat: Infinity, ease: 'linear' }} />
                  : <Globe size={15} />
                }
              </motion.button>
            )}
            {isLocked ? (
              <motion.button whileTap={{ scale: 0.9 }} onClick={() => setShowPlusModal(true)} className="w-10 h-10 rounded-full bg-gradient-to-br from-amber-400 to-orange-500 flex items-center justify-center shadow-lg shrink-0">
                <Crown size={18} className="text-white drop-shadow-sm" />
              </motion.button>
            ) : (
              <button onClick={() => { triggerHaptic("medium"); sendMessage(); }} disabled={!message.trim()} className="w-10 h-10 rounded-full gradient-primary flex items-center justify-center transition-transform active:scale-90 disabled:opacity-30 shrink-0">
                <Send size={18} className="text-white ml-0.5" />
              </button>
            )}
          </div>
      </div>

      <MeetProposalModal showMeetProposal={showMeetProposal} setShowMeetProposal={setShowMeetProposal} meetDate={meetDate} setMeetDate={setMeetDate} meetPlace={meetPlace} setMeetPlace={setMeetPlace} handleMeetProposal={handleMeetProposal} />
      <ScheduleShareModal showScheduleModal={showScheduleModal} setShowScheduleModal={setShowScheduleModal} scheduleDate={scheduleDate} setScheduleDate={setScheduleDate} scheduleText={scheduleText} setScheduleText={setScheduleText} handleScheduleShare={handleScheduleShare} />
      <ReportModal showReportModal={showReportModal} setShowReportModal={setShowReportModal} thread={thread} reportReason={reportReason} setReportReason={setReportReason} handleReport={handleReport} />
      <DeleteConfirmModal showDeleteConfirm={showDeleteConfirm} setShowDeleteConfirm={setShowDeleteConfirm} selectedChat={selectedChat} handleDeleteChat={handleDeleteChat} />
      <MigoPlusModal isOpen={showPlusModal} onClose={() => setShowPlusModal(false)} />
      <SOSModal 
        isOpen={showSOS} 
        onClose={() => {
          setShowSOS(false);
          if (thread?.opponentId || selectedChat) {
            setSelectedChat(null);
          }
        }} 
        targetUserId={thread?.opponentId}
        targetGroupId={selectedChat}
      />
      <ProfileDetailSheet profile={viewingProfile} onClose={() => setViewingProfile(null)} showActions={false} />
      <ReportBlockActionSheet isOpen={!!actionSheetTarget} onClose={() => setActionSheetTarget(null)} targetType={actionSheetTarget?.isGroup ? "group" : "user"} targetId={actionSheetTarget?.isGroup ? actionSheetTarget?.id : (actionSheetTarget?.opponentId ?? "")} targetName={actionSheetTarget?.name ?? ""} />
    </div>
  );
};

import i18n from "@/i18n";
import React from "react";
import { motion } from "framer-motion";
import { Lock, Users, MessageCircle } from "lucide-react";
import { useTranslation } from "react-i18next";
import { toast } from "@/hooks/use-toast";
import type { GroupThread } from "@/context/ChatContext";

export interface ChatThreadListProps {
  filteredThreads: any[];
  searchQuery: string;
  swipedChatId: string | null;
  setSwipedChatId: (id: string | null) => void;
  mutedChats: string[];
  canOpenChat: (id: string) => boolean;
  setShowPlusModal: (v: boolean) => void;
  setSelectedChat: (id: string | null) => void;
  handleDeleteChat: (id: string) => void;
  setShowReportModal: (v: boolean) => void;
  markRead: (id: string) => void;
}

export const ChatThreadList: React.FC<ChatThreadListProps> = ({
  filteredThreads,
  searchQuery,
  swipedChatId,
  setSwipedChatId,
  mutedChats,
  canOpenChat,
  setShowPlusModal,
  setSelectedChat,
  handleDeleteChat,
  setShowReportModal,
  markRead
}) => {
  const { t } = useTranslation();

  return (
    <div className="px-0 pb-28 pt-2">
      {filteredThreads.length === 0 ? (
        /* Empty State */
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.1, duration: 0.3 }}
          className="flex flex-col items-center text-center pt-20 pb-8 px-6"
        >
          <div className="relative mb-6">
            <div className="w-24 h-24 rounded-[32px] bg-muted/60 flex items-center justify-center shadow-inner border border-white/10">
              <MessageCircle size={36} className="text-muted-foreground/50" />
            </div>
          </div>
          <h3 className="text-lg font-extrabold text-foreground mb-1.5 tracking-tight truncate">
            {searchQuery ? i18n.t("auto.g_1389", "검색 결과 없음") : i18n.t("auto.g_1390", "아직 대화가 없어요")}
          </h3>
          <p className="text-[13px] font-medium text-muted-foreground mb-8 leading-relaxed max-w-[200px] truncate">
            {searchQuery
              ? i18n.t("auto.g_1391", "Try a different keyword")
              : i18n.t("auto.g_1394", "Say hi to a traveler you like ✈️")}
          </p>
          {!searchQuery && (
            <motion.button
              whileTap={{ scale: 0.95 }}
              onClick={() => { window.location.hash = '/'; }}
              className="px-6 py-3.5 rounded-full bg-foreground text-background font-bold text-[13px] shadow-md flex items-center gap-2 hover:opacity-90 transition-opacity"
            >
              {i18n.t("auto.g_1385", "Browse Travelers")}</motion.button>
          )}
        </motion.div>
      ) : (
        <div className="flex flex-col truncate">
          {filteredThreads.map((chat, idx, arr) => {
            const groupChat = chat as GroupThread;
            const isLocked = !canOpenChat(chat.id);
            const isLast = idx === arr.length - 1;

            let isNewMatch = false;
            let expiresIn = "";
            if (!groupChat.isGroup && (chat.lastMessage === "New conversation" || !chat.lastMessage) && groupChat.createdAt) {
              isNewMatch = true;
              const created = new Date(groupChat.createdAt).getTime();
              const diff = 24 * 60 * 60 * 1000 - (Date.now() - created);
              if (diff > 0) {
                const h = Math.floor(diff / 3600000);
                const m = Math.floor((diff % 3600000) / 60000);
                expiresIn = `${h}h ${m}m`;
              }
            }

            return (
              <div key={chat.id} className="relative w-full overflow-hidden bg-background">
                {/* Underlay Left (Swipe Right actions) */}
                <div className="absolute inset-y-0 left-0 flex items-stretch">
                  <button onClick={() => { setSwipedChatId(null); handleDeleteChat(chat.id); }} className="px-5 bg-red-500 text-white font-extrabold text-[13px] flex items-center justify-center transition-opacity hover:opacity-90">{i18n.t("auto.g_1386", "Leave")}</button>
                  <button onClick={() => { setSwipedChatId(null); setSelectedChat(chat.id); setShowReportModal(true); }} className="px-5 bg-orange-500 text-white font-extrabold text-[13px] flex items-center justify-center transition-opacity hover:opacity-90">{i18n.t("auto.g_1387", "Report")}</button>
                </div>
                {/* Underlay Right (Swipe Left action feedback) */}
                <div className="absolute inset-y-0 right-0 flex items-stretch">
                  <div className="px-6 bg-emerald-500 text-white font-extrabold text-[13px] flex items-center justify-center truncate">{i18n.t("auto.g_1388", "Mark Read")}</div>
                </div>

                <motion.div
                  drag="x"
                  dragDirectionLock
                  dragConstraints={{ left: 0, right: swipedChatId === chat.id ? 140 : 0 }}
                  animate={{ x: swipedChatId === chat.id ? 140 : 0 }}
                  initial={{ opacity: 0, y: 10 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true, margin: "100px" }}
                  transition={{ type: "spring", stiffness: 400, damping: 30 }}
                  onDragEnd={(e, info) => {
                    if (swipedChatId === chat.id) {
                      if (info.offset.x < -30) setSwipedChatId(null);
                    } else {
                      if (info.offset.x > 50) {
                        setSwipedChatId(chat.id);
                      } else if (info.offset.x < -50) {
                        markRead(chat.id);
                        toast({ title: i18n.t("auto.g_0051", "Marked as read.") });
                        setSwipedChatId(null);
                      }
                    }
                  }}
                  className="relative z-10 w-full"
                >
                  <button
                    onClick={() => {
                      if (swipedChatId === chat.id) setSwipedChatId(null);
                      else {
                        if (isLocked) { setShowPlusModal(true); return; }
                        setSelectedChat(chat.id);
                      }
                    }}
                    className={`w-full flex items-center gap-4 px-5 py-3 transition-colors active:bg-muted/50 bg-background ${swipedChatId === chat.id ? 'shadow-[4px_0_15px_rgba(0,0,0,0.1)] rounded-xl' : ''} ${isLocked ? 'opacity-60' : ''}`}
                  >
                    {/* Avatar */}
                    <div className="relative shrink-0 py-1">
                      {groupChat.isGroup && groupChat.memberPhotos && groupChat.memberPhotos.length >= 2 ? (
                        <div className="w-[52px] h-[52px] relative">
                          <img src={groupChat.memberPhotos[0]} alt="" className="w-9 h-9 rounded-full object-cover absolute top-0 left-0 border-2 border-background shadow-sm" loading="lazy" />
                          <img src={groupChat.memberPhotos[1]} alt="" className="w-9 h-9 rounded-full object-cover absolute bottom-0 right-0 border-2 border-background shadow-sm" loading="lazy" />
                        </div>
                      ) : chat.photo ? (
                        <img src={chat.photo} alt="" className="w-[52px] h-[52px] rounded-full object-cover shadow-sm border border-border/30" loading="lazy" onError={e => { (e.target as HTMLImageElement).style.display = 'none'; }} />
                      ) : (
                        <div className="w-[52px] h-[52px] rounded-full gradient-primary flex items-center justify-center text-primary-foreground text-xl font-extrabold shadow-sm">
                          {chat.name?.[0] ?? "?"}
                        </div>
                      )}
                      {/* Online indicator */}
                      {!groupChat.isGroup && chat.online && (
                        <div className="absolute bottom-0 right-0 w-3.5 h-3.5 rounded-full bg-emerald-500 border-2 border-background" />
                      )}
                      {/* Group badge */}
                      {groupChat.isGroup && (
                        <div className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full bg-primary flex items-center justify-center border-2 border-background">
                          <Users size={10} className="text-white" />
                        </div>
                      )}
                      {/* Muted badge */}
                      {mutedChats.includes(chat.id) && (
                        <div className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-background border border-border flex items-center justify-center">
                          <span className="text-[7px]">🔕</span>
                        </div>
                      )}
                    </div>

                    {/* Content wrapped with border-b for seamless list */}
                    <div className={`flex-1 min-w-0 text-left py-3 flex items-center gap-2 ${!isLast && swipedChatId !== chat.id ? 'border-b border-border/40' : ''}`}>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-baseline justify-between gap-2 mb-1">
                          <div className="flex items-center gap-1.5 min-w-0">
                            <span className="font-extrabold text-[15px] text-foreground truncate">{chat.name}</span>
                            {groupChat.isGroup && (
                              <span className="text-[9px] font-bold px-1.5 py-0.5 rounded-sm bg-muted text-muted-foreground shrink-0 leading-none">
                                {groupChat.memberCount}
                              </span>
                            )}
                          </div>
                          <span className={`text-[11px] font-bold shrink-0 ${chat.unread > 0 ? "text-primary" : "text-muted-foreground/60"}`}>{chat.time}</span>
                        </div>
                        <p className={`text-[13px] truncate leading-tight flex items-center gap-1 ${chat.unread > 0 || isNewMatch ? "font-bold text-foreground" : "font-medium text-muted-foreground line-clamp-2 white-space-normal"}`}>
                          {isLocked 
                            ? i18n.t("auto.g_1392", "🔒 You have a message. Upgrade to Plus to view.") 
                            : isNewMatch && expiresIn
                              ? <span className="text-amber-500 flex items-center gap-1"><MessageCircle size={12} /> {i18n.t("chat.newMatch", "새로운 매치!")} <span className="text-xs bg-amber-500/10 px-1.5 rounded text-amber-600 ml-0.5">⏳ {expiresIn}</span></span>
                              : isNewMatch
                                ? <span className="text-muted-foreground">{i18n.t("chat.expiredMatch", "만료된 매치")}</span>
                                : chat.lastMessage
                          }
                        </p>
                      </div>

                      {/* Right badge */}
                      {chat.unread > 0 && !isLocked ? (
                        <div className="min-w-[22px] h-[22px] rounded-full bg-primary flex items-center justify-center shrink-0 px-1.5 shadow-sm transform transition-transform animate-in zoom-in">
                          <span className="text-[10px] font-black text-white">{chat.unread > 99 ? '99+' : chat.unread}</span>
                        </div>
                      ) : isLocked ? (
                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-amber-400 to-orange-500 shadow-md flex items-center justify-center shrink-0 mt-2">
                          <Lock size={12} className="text-white shrink-0 drop-shadow-sm" />
                        </div>
                      ) : null}
                    </div>
                  </button>
                </motion.div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

import i18n from "@/i18n";
import { AnimatePresence, motion } from "framer-motion";
import { MessageCircle, MapPin, Trash2 } from "lucide-react";
import { useTranslation } from "react-i18next";

interface DiscoverPostsProps {
  activeTab: string;
  loadingPosts: boolean;
  sortedPosts: any[];
  readStories: Set<string>;
  handleStoryClick: (index: number, postId: string) => void;
  deletePost: (postId: string) => void;
  user: any;
}

export const DiscoverPosts = ({
  activeTab,
  loadingPosts,
  sortedPosts,
  readStories,
  handleStoryClick,
  deletePost,
  user
}: DiscoverPostsProps) => {
  return (
    <AnimatePresence mode="wait">
      {activeTab === "community" && <motion.div
        key="community"
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -8 }}
        transition={{ duration: 0.18 }}
        className="px-4 space-y-3 pt-2 pb-24"
      >
        {loadingPosts ? <div className="flex items-center justify-center py-16">
            <motion.div className="w-8 h-8 rounded-full gradient-primary" animate={{
        scale: [1, 1.2, 1]
      }} transition={{
        repeat: Infinity,
        duration: 1
      }} />
          </div> : sortedPosts.length === 0 ? <div className="text-center py-16">
            <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mx-auto mb-4">
              <MessageCircle size={24} className="text-muted-foreground" />
            </div>
            <p className="text-muted-foreground text-sm text-center">{i18n.t("auto.g_1393", "Be the first to post!")}</p>
          </div> : <div className="flex flex-col gap-5 px-1">
            {sortedPosts.map((post: any, index: number) => {
              const isRead = readStories.has(post.id);
              return (
               <motion.div 
                key={post.id} 
                initial={{ opacity: 0, y: 15 }} 
                animate={{ opacity: 1, y: 0 }} 
                className={`w-full aspect-[4/5] rounded-[24px] cursor-pointer shadow-md group p-[3px] ${!isRead ? 'bg-gradient-to-tr from-amber-400 via-orange-500 to-pink-500' : 'bg-transparent'}`}
                onClick={() => handleStoryClick(index, post.id)}
               >
                <div className="relative w-full h-full bg-muted rounded-[21px] overflow-hidden">
                  {/* Thumbnail Image */}
                  {(post.images?.[0] || post.imageUrl) ? (
                    <img 
                      src={post.images?.[0] || post.imageUrl} 
                      className="w-full h-full object-cover transition-transform duration-700" 
                      loading="lazy"
                    />
                  ) : (
                    <div className="w-full h-full gradient-primary flex items-center justify-center p-6">
                      <p className="text-white font-extrabold text-[18px] leading-relaxed drop-shadow-md break-keep whitespace-pre-wrap text-center">{post.content}</p>
                    </div>
                  )}

                  {/* Overlay Gradient for readability */}
                  <div className="absolute inset-x-0 bottom-0 top-1/2 bg-gradient-to-t from-black/90 via-black/40 to-transparent pointer-events-none" />

                  {/* Profile info on top */}
                  <div className="absolute top-4 left-4 flex items-center gap-2 bg-black/30 backdrop-blur-md rounded-full pr-3 p-1 border border-white/20 shadow-sm">
                    <img src={post.photo} className="w-8 h-8 rounded-full object-cover border-2 border-white/80" />
                    <div className="flex flex-col">
                      <span className="text-[12px] font-bold text-white leading-none drop-shadow-sm">{post.author}</span>
                      <span className="text-[9px] font-medium text-white/80">{post.time}</span>
                    </div>
                  </div>

                  {/* Location, Action & Content info at bottom */}
                  <div className="absolute bottom-4 inset-x-4 flex flex-col gap-3">
                    {post.content && (post.images?.[0] || post.imageUrl) && (
                      <p className="text-white text-[14px] font-semibold line-clamp-2 leading-snug drop-shadow-md">
                        {post.content}
                      </p>
                    )}

                    <div className="flex items-end justify-between truncate">
                      <div className="flex items-center gap-2">
                        {post.locationTag && (
                          <div className="text-[11px] text-white/95 flex items-center gap-1 bg-black/40 px-2.5 py-1.5 rounded-xl backdrop-blur-md border border-white/10">
                            <MapPin size={12} className="text-white" />
                            <span className="truncate max-w-[120px] font-bold">{post.locationTag.name}</span>
                          </div>
                        )}
                      </div>

                      {user && post.authorId === user.id && (
                         <button onClick={e => {
                           e.stopPropagation();
                           deletePost(post.id);
                         }} className="w-8 h-8 rounded-full bg-red-500/80 flex items-center justify-center hover:bg-red-500 transition-colors backdrop-blur-md shadow-sm">
                           <Trash2 size={14} className="text-white" />
                         </button>
                      )}
                    </div>
                  </div>
                </div>
               </motion.div>
              );
            })}
          </div>}
      </motion.div>}
    </AnimatePresence>
  );
};

