        </div>
      </div>
      <button
        onClick={() => navigate("/find-account", { state: { tab: "password" } })}
        className="text-xs text-primary font-semibold text-right w-full"
      >
        {t('login.forgotPass')}
      </button>

      <div className="space-y-2 pt-2">
        <p className="text-[10px] text-center text-muted-foreground truncate">{t('login.orSocial')}</p>

        {/* Google OAuth — Custom Tab / SFSafariViewController (앱 내 처리) */}
        <motion.button
          whileTap={{ scale: 0.97 }}
          onClick={async () => {
            try {
              const isNative = Capacitor.isNativePlatform();
              const { data, error } = await supabase.auth.signInWithOAuth({
                provider: "google",
                options: {
                  redirectTo: isNative
                    ? 'migoapp://login-callback'
                    : window.location.origin,
                  skipBrowserRedirect: isNative, // 네이티브만 수동 브라우저, 웹은 자동 리다이렉트
                }
              });
              if (error) {
                toast({ title: i18n.t("auto.g_0052", "구글 로그인 오류"), description: error.message, variant: "destructive" });
              } else if (isNative && data?.url) {
                // SFSafariViewController (iOS) / Chrome Custom Tab (Android)
                await Browser.open({ url: data.url, presentationStyle: 'popover' });
              }
              // 웹: skipBrowserRedirect=false이므로 현재 페이지가 자동으로 Google로 이동됨
            } catch (e: any) {
              toast({ title: i18n.t("auto.g_0052", "구글 로그인 오류"), description: e?.message, variant: "destructive" });
            }
          }}
          className="w-full flex items-center justify-center gap-2 py-3 rounded-2xl text-sm font-bold shadow-sm transition-transform bg-card border border-border text-foreground"
        >
          <span>🔵</span> {i18n.t("login.google")}
        </motion.button>

        {/* Sign in with Apple — Guideline 4.8 필수 구현 */}
        <motion.button
          whileTap={{ scale: 0.97 }}
          onClick={async () => {
            try {
              if (Capacitor.getPlatform() === 'ios') {
                const { SignInWithApple } = await import('@capacitor-community/apple-sign-in');

                const result = await SignInWithApple.authorize({
                  clientId: 'com.lunaticsgroup.migo', // iOS 네이티브: 앱 번들 ID
                  redirectURI: '',
                  scopes: 'email name',
                  // CSRF 방지: 매 요청마다 안전한 임의 state 생성 (Math.random 사용 금지)
                  state: (typeof crypto !== 'undefined' && crypto.randomUUID) 
                    ? crypto.randomUUID() 
                    : Array.from(crypto.getRandomValues(new Uint8Array(16))).map(b => b.toString(16).padStart(2, '0')).join(''),
                });

                if (result?.response?.identityToken) {
                  const { error } = await supabase.auth.signInWithIdToken({
                    provider: 'apple',
                    token: result.response.identityToken,
                  });
                  if (error) throw error;
                }
              } else {
                const { data, error } = await supabase.auth.signInWithOAuth({
                  provider: "apple",
                  options: {
                    redirectTo: Capacitor.isNativePlatform()
                      ? 'migoapp://login-callback'
                      : window.location.origin,
                    skipBrowserRedirect: Capacitor.isNativePlatform(),
                  }
                });
                if (error) {
                  toast({ title: i18n.t("login.apple"), description: error.message, variant: "destructive" });
                } else if ((data as any)?.url && Capacitor.isNativePlatform()) {
                  await Browser.open({ url: (data as any).url, presentationStyle: 'popover' });
                }
              }
            } catch (e: any) {
              toast({ title: i18n.t("login.apple"), description: e?.message, variant: "destructive" });
            }
          }}
          className="w-full flex items-center justify-center gap-2 py-3 rounded-2xl text-sm font-bold shadow-sm transition-transform bg-foreground text-background"
        >
          <span>🍎</span> {i18n.t("login.apple")}
        </motion.button>
      </div>

      <div className="flex items-center gap-2 p-3 rounded-2xl bg-primary/5 border border-primary/20 mt-4">
        <Shield size={13} className="text-primary shrink-0" />
        <p className="text-[10px] text-muted-foreground truncate">{t('login.sslNote')}</p>
      </div>
    </motion.div>
  );
};

import i18n from "@/i18n";
import { AnimatePresence, motion } from "framer-motion";
import { Users, X } from "lucide-react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";

interface GroupSheetProps {
  selectedGroup: any | null;
  setSelectedGroup: (group: any | null) => void;
  myLatLngRef: React.MutableRefObject<{ lat: number; lng: number } | null>;
  calcDist: (lat1: number, lon1: number, lat2: number, lon2: number) => number;
  distLabel: (dist: number) => string;
}

export const GroupSheet = ({
  selectedGroup,
  setSelectedGroup,
  myLatLngRef,
  calcDist,
  distLabel
}: GroupSheetProps) => {
  const { t } = useTranslation();
  const navigate = useNavigate();

  return (
    <AnimatePresence>
      {selectedGroup && <motion.div className="absolute left-4 right-4 z-30" style={{ bottom: "calc(95px + env(safe-area-inset-bottom, 0px))" }} initial={{
      y: 40,
      opacity: 0
    }} animate={{
      y: 0,
      opacity: 1
    }} exit={{
      y: 40,
      opacity: 0
    }} transition={{
      type: "spring",
      damping: 25,
      stiffness: 300
    }}>
          <div className="bg-card rounded-3xl p-4 shadow-float border border-border/60 flex flex-col transition-all relative overflow-hidden">
            {/* Close button for sheet */}
             <button onClick={(e) => { e.stopPropagation(); setSelectedGroup(null); }} className="absolute top-3 right-3 w-7 h-7 rounded-full bg-muted/60 flex items-center justify-center z-20 hover:bg-muted">
               <X size={14} className="text-muted-foreground" />
             </button>
            <div className="flex items-start gap-3.5 relative z-10 w-full pr-8">
              {/* 이미지 */}
              <div className="relative shrink-0 mt-0.5">
                {selectedGroup.coverImage ? (
                  <img src={selectedGroup.coverImage} className="w-14 h-14 rounded-2xl object-cover shadow-sm cursor-pointer border border-border/50" onClick={() => setSelectedGroup(null)} onError={e => { (e.target as HTMLImageElement).style.display = 'none'; }} />
                ) : (
                  <div className="w-14 h-14 rounded-2xl bg-primary/10 flex items-center justify-center text-3xl shadow-sm border border-primary/20">
                    🛩️
                  </div>
                )}
              </div>

              {/* 메인 정보 */}
              <div className="flex-1 min-w-0 pb-1">
                <div className="flex items-center gap-1.5 mb-1.5">
                   <span className="text-[10px] font-extrabold text-primary bg-primary/10 px-2 py-0.5 rounded-full whitespace-nowrap overflow-hidden text-ellipsis">
                     {selectedGroup.isPremiumGroup ? i18n.t("map.premium") : i18n.t("auto.g_1471", "동행 모집")}
                   </span>
                </div>
                <h4 className="font-extrabold text-[16px] text-foreground leading-tight overflow-hidden text-ellipsis">{selectedGroup.title}</h4>
                <p className="text-[12px] font-medium text-muted-foreground overflow-hidden text-ellipsis mt-1.5 flex items-center gap-1">
                  <Users size={12} className="inline text-muted-foreground shrink-0" />
                  <span className="overflow-hidden text-ellipsis">{selectedGroup.currentMembers}/{selectedGroup.maxMembers}{i18n.t("auto.g_1465", "명 · 📍")}{selectedGroup.destination}</span>
                </p>
              </div>
            </div>

            {/* 하단 거리 정보 및 버튼 박스 */}
            <div className="flex items-center justify-between gap-3 border-t border-border/40 mt-3 pt-3">
              <div className="min-w-0 truncate">
                {(() => {
                  if (!myLatLngRef.current || !selectedGroup.lat || !selectedGroup.lng) return <div className="text-[12px] text-muted-foreground font-medium truncate">{i18n.t("auto.g_1466", "위치 확인 불가")}</div>;
                  const d = calcDist(myLatLngRef.current.lat, myLatLngRef.current.lng, selectedGroup.lat, selectedGroup.lng);
                  const walkTime = Math.max(1, Math.ceil((d * 1000) / 75));
                  return (
                    <div className="flex items-center gap-1 text-[13px] font-black text-primary truncate">
                      <span className="truncate">{i18n.t("auto.g_1467", "🚶 약")}{walkTime}{i18n.t("auto.g_1468", "분")}</span>
                      <span className="text-primary/40 text-[10px]">●</span>
                      <span className="opacity-80 font-bold">{distLabel(d)}</span>
                    </div>
                  );
                })()}
              </div>

              <div className="flex items-center gap-2 shrink-0 truncate">
                {selectedGroup.lat && selectedGroup.lng && (
                  <a
                    href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(selectedGroup.destination || `${selectedGroup.lat},${selectedGroup.lng}`)}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="px-3.5 py-2 rounded-xl bg-secondary/60 text-secondary-foreground text-[12px] font-bold hover:bg-secondary/80 transition-colors flex items-center justify-center border border-border"
                  >
                    {i18n.t("auto.g_1469", "지도 검색")}</a>
                )}
                <button 
                  onClick={() => navigate("/trip-match", { state: { detailGroup: selectedGroup } })}
                  className="px-4 py-2 rounded-xl gradient-primary text-white text-[12px] font-extrabold shadow-md active:scale-95 transition-transform flex items-center"
                >
                  {i18n.t("auto.g_1470", "자세히 보기")}
                </button>
              </div>
            </div>
          </div>
        </motion.div>}
    </AnimatePresence>
  );
};

/**
 * HotplaceSheet.tsx
 * ──────────────────────────────────────────────────────────────────
 * 핫플레이스 상세 바텀시트 ─ 동반자 구하기 기능 포함
 *
 * 기능:
 * 1. 핫플레이스 이름/국가/거리/카테고리 정보 표시
 * 2. 현재 그 장소에서 동반자 구하는 유저 목록 (DB: hotplace_seekers)
 * 3. "나도 구인" 등록 / 취소
 * 4. 동반자 신청 → trip_groups 자동 생성
 * 5. 가상 투입 / 클룩 예매 / 구글지도 바로가기
 */
import { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, Users, Plus, MapPin, Zap, Calendar, Globe, ChevronRight, UserPlus, Check } from "lucide-react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/lib/supabaseClient";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "@/hooks/use-toast";
import { Hotplace } from "@/lib/placeRecommendations";

// ─── types ────────────────────────────────────────────────────────

interface Seeker {
  id: string;
  user_id: string;
  hotplace_id: string;
  message: string | null;
  meet_date: string | null;    // YYYY-MM-DD
  meet_time: string | null;    // HH:MM
  max_members: number | null;  // 2~10
  created_at: string;
  profiles: {
    name: string;
    photo_url: string | null;
    age: number | null;
    nationality: string | null;
    bio: string | null;
  } | null;
}

interface Props {
  hotplace: Hotplace | null;
  myLatLngRef: React.MutableRefObject<{ lat: number; lng: number } | null>;
  calcDist: (lat1: number, lon1: number, lat2: number, lon2: number) => number;
  distLabel: (d: number) => string;
  onClose: () => void;
  onFlyTo: (h: Hotplace) => void;
  onProfileClick?: (userId: string) => void;
}

// ─── category style map ───────────────────────────────────────────
const CATEGORY_STYLES: Record<string, { color: string; bg: string }> = {
  city:       { color: "text-blue-600",    bg: "bg-blue-50" },
  nature:     { color: "text-emerald-600", bg: "bg-emerald-50" },
  attraction: { color: "text-purple-600",  bg: "bg-purple-50" },
  club:       { color: "text-pink-600",    bg: "bg-pink-50" },
};

// ─── Component ───────────────────────────────────────────────────

export const HotplaceSheet = ({
  hotplace,
  myLatLngRef,
  calcDist,
  distLabel,
  onClose,
  onFlyTo,
  onProfileClick,
}: Props) => {
  const { t } = useTranslation();
  const { user } = useAuth();

  const [seekers, setSeekers]           = useState<Seeker[]>([]);
  const [loading, setLoading]           = useState(false);
  const [mySeekerId, setMySeekerId]     = useState<string | null>(null);
  const [myMessage, setMyMessage]       = useState("");
  const [myMeetDate, setMyMeetDate]     = useState("");          // YYYY-MM-DD
  const [myMeetTime, setMyMeetTime]     = useState("");          // HH:MM
  const [myMaxMembers, setMyMaxMembers] = useState(4);           // 기본 4명
  const [showMsgInput, setShowMsgInput] = useState(false);
  const [joining, setJoining]           = useState<string | null>(null);
  const [activeTab, setActiveTab]       = useState<"info" | "seekers">("info");

  // ── 동반자 구인 목록 로드 ─────────────────────────────────────
  const loadSeekers = useCallback(async () => {
    if (!hotplace) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from("hotplace_seekers")
        .select(`
          id, user_id, hotplace_id, message, meet_date, meet_time, max_members, created_at,
          profiles (name, photo_url, age, nationality, bio)
        `)
        .eq("hotplace_id", hotplace.id)
        .order("created_at", { ascending: false });

      if (error) {
        // 테이블이 아직 생성되지 않은 경우 등 — 조용히 실패
        console.warn("[HotplaceSheet] hotplace_seekers load failed:", error.message);
        setSeekers([]);
        return;
      }
      if (data) {
        setSeekers(data as Seeker[]);
        const mine = data.find((s: any) => s.user_id === user?.id);
        setMySeekerId(mine ? mine.id : null);
        if (mine) setMyMessage(mine.message || "");
      }
    } finally {
      setLoading(false);
    }
  }, [hotplace, user?.id]);

  useEffect(() => {
    if (hotplace) {
      setSeekers([]);
      setMySeekerId(null);
      setMyMessage("");
      setMyMeetDate("");
      setMyMeetTime("");
      setMyMaxMembers(4);
      setShowMsgInput(false);
      setActiveTab("info");
      loadSeekers();
    }
  }, [hotplace?.id]);

  // ── 구인 등록 ─────────────────────────────────────────────────
  const handleRegisterSeeker = async () => {
    if (!user || !hotplace) return;
    const { data, error } = await supabase
      .from("hotplace_seekers")
      .insert({
        user_id: user.id,
        hotplace_id: hotplace.id,
        message: myMessage.trim() || null,
        meet_date: myMeetDate || null,
        meet_time: myMeetTime || null,
        max_members: myMaxMembers,
      })
      .select("id")
      .single();
    if (!error && data) {
      setMySeekerId(data.id);
      setShowMsgInput(false);
      await loadSeekers();
      toast({ title: t("hotplace.seekerRegistered", "✅ 동반자 구인 등록 완료!"), description: hotplace.name });
      setActiveTab("seekers");
    }
  };

  // ── 구인 취소 ─────────────────────────────────────────────────
  const handleCancelSeeker = async () => {
    if (!mySeekerId) return;
    await supabase.from("hotplace_seekers").delete().eq("id", mySeekerId);
    setMySeekerId(null);
    setMyMessage("");
    await loadSeekers();
    toast({ title: t("hotplace.seekerCancelled", "구인 취소됨") });
  };

  // ── 함께 가자! 신청 ───────────────────────────────────────────
  const handleJoin = async (seeker: Seeker) => {
    if (!user || !hotplace || joining) return;
    setJoining(seeker.user_id);
    try {
      // 이미 둘 사이 그룹 있는지 확인
      const { data: existing } = await supabase
        .from("trip_groups")
        .select("id")
        .contains("tags", [`_loc_:${hotplace.lat}:${hotplace.lng}`])
        .eq("host_id", seeker.user_id)
        .limit(1)
        .maybeSingle();

      let groupId: string;

      if (existing) {
        groupId = existing.id;
        // 이미 있으면 멤버로 합류
        await supabase.from("trip_group_members").upsert(
          { group_id: groupId, user_id: user.id },
          { onConflict: "group_id,user_id" }
        );
      } else {
        // 새 그룹 생성
        const { data: grp, error } = await supabase
          .from("trip_groups")
          .insert({
            title: `${hotplace.emoji} ${hotplace.name.split(" (")[0]} 같이 가요!`,
            destination: `${hotplace.name}, ${hotplace.country}`,
            dates: t("map.today", "오늘"),
            description: seeker.message || t("hotplace.defaultDesc", "함께 여행할 동반자를 찾고 있어요 😊"),
            host_id: seeker.user_id,
            max_members: 6,
            status: "recruiting",
            tags: [`_loc_:${hotplace.lat}:${hotplace.lng}`, hotplace.category, hotplace.name.split(" (")[0]],
          })
          .select("id")
          .single();
        if (error || !grp) throw error;
        groupId = grp.id;

        await supabase.from("trip_group_members").insert([
          { group_id: groupId, user_id: seeker.user_id },
          { group_id: groupId, user_id: user.id },
        ]);
      }

      // 알림 전송
      await supabase.from("in_app_notifications").insert({
        user_id: seeker.user_id,
        type: "match",
        title: t("hotplace.joinNotifTitle", "동반자 신청이 왔어요! 🎉"),
        content: t("hotplace.joinNotifBody", `${user.name || "누군가"}님이 ${hotplace.name.split(" (")[0]}에서 함께 가고 싶어합니다!`),
      });

      toast({
        title: t("hotplace.joinSuccess", "🎉 함께 가기 신청 완료!"),
        description: t("hotplace.joinDesc", "그룹이 만들어졌어요. 채팅에서 확인하세요."),
      });
    } catch (err) {
      console.error(err);
      toast({ title: t("hotplace.joinFail", "신청 실패"), variant: "destructive" });
    } finally {
      setJoining(null);
    }
  };

  const catStyles = hotplace ? (CATEGORY_STYLES[hotplace.category] ?? { color: "text-primary", bg: "bg-primary/10" }) : null;
  const catLabel = hotplace ? (
    hotplace.category === "city" ? `🏙️ ${t("auto.ko_0202", "City center")}` :
    hotplace.category === "nature" ? `🌊 ${t("auto.ko_0203", "Beach / Nature")}` :
    hotplace.category === "attraction" ? `🎡 ${t("auto.ko_0204", "Theme park / Attraction")}` :
    hotplace.category === "club" ? `🪩 ${t("auto.ko_0205", "Club / Lounge")}` :
    hotplace.category
  ) : null;

  const distInfo = (() => {
    if (!myLatLngRef.current || !hotplace) return null;
    const d = calcDist(myLatLngRef.current.lat, myLatLngRef.current.lng, hotplace.lat, hotplace.lng);
    return { label: distLabel(d), walk: Math.max(1, Math.ceil((d * 1000) / 75)) };
  })();

  return (
    <AnimatePresence>
      {hotplace && (
        <>
          {/* Backdrop */}
          <motion.div
            className="absolute inset-0 z-40 bg-black/20 backdrop-blur-[1px]"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
          />

          {/* Bottom Sheet */}
          <motion.div
            className="absolute left-0 right-0 z-50 bg-white dark:bg-zinc-900 rounded-t-3xl shadow-[0_-8px_40px_rgba(0,0,0,0.18)] border-t border-black/5 dark:border-white/5 flex flex-col"
            style={{ bottom: 0, maxHeight: "82vh" }}
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 28, stiffness: 320 }}
            drag="y"
            dragConstraints={{ top: 0, bottom: 0 }}
            dragElastic={{ top: 0, bottom: 0.3 }}
            onDragEnd={(_, i) => { if (i.offset.y > 80) onClose(); }}
          >
            {/* Handle bar */}
            <div className="flex justify-center pt-3 pb-1 shrink-0">
              <div className="w-10 h-1.5 rounded-full bg-black/10 dark:bg-white/10" />
            </div>

            {/* ── HEADER ── */}
            <div className="px-5 pb-3 shrink-0">
              <div className="flex items-start gap-3">
                <div className="w-14 h-14 rounded-2xl gradient-primary flex items-center justify-center text-2xl shadow-md shrink-0">
                  {hotplace.emoji}
                </div>
                <div className="flex-1 min-w-0">
                  <h2 className="font-extrabold text-[17px] text-foreground leading-tight">{hotplace.name}</h2>
                  <p className="text-sm text-muted-foreground mt-0.5 truncate">
                    {hotplace.country} · {hotplace.cities[0]}
                  </p>
                  <div className="flex items-center gap-2 mt-1.5 flex-wrap">
                    {catStyles && (
                      <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${catStyles.bg} ${catStyles.color}`}>
                        {catLabel}
                      </span>
                    )}
                    {distInfo && (
                      <span className="text-[10px] font-bold text-teal-600 bg-teal-50 px-2 py-0.5 rounded-full flex items-center gap-1">
                        <MapPin size={9} /> {distInfo.label} · 🚶 {distInfo.walk}{t("auto.ko_0132", "분")}
                      </span>
                    )}
                  </div>
                </div>
                <button
                  onClick={onClose}
                  className="w-9 h-9 rounded-full bg-black/5 dark:bg-white/10 flex items-center justify-center shrink-0"
                >
                  <X size={16} className="text-muted-foreground" />
                </button>
              </div>

              {/* Seeker count badge */}
              {seekers.length > 0 && (
                <div className="mt-3 flex items-center gap-2 bg-amber-50 border border-amber-200 px-3 py-2 rounded-xl">
                  <Zap size={14} className="text-amber-500 shrink-0" fill="currentColor" />
                  <p className="text-xs font-bold text-amber-700">
                    {t("hotplace.seekerCount", `지금 ${seekers.length}명이 동반자를 찾고 있어요!`).replace("${seekers.length}", String(seekers.length))}
                  </p>
                </div>
              )}
            </div>

            {/* ── TABS ── */}
            <div className="px-5 shrink-0 flex gap-1 pb-2">
              {([
                { id: "info", label: t("hotplace.tabInfo", "장소 정보") },
                { id: "seekers", label: `${t("hotplace.tabSeekers", "동반자 구하기")}${seekers.length > 0 ? ` (${seekers.length})` : ""}` },
